#[cfg(all(test, feature = "ts"))]
mod tests {
    use super::*;
    use std::io::Write;
    use std::path::PathBuf;
    use ts_rs::TS;

    /// Run with: cargo test -p opensession-api-types -- export_typescript --nocapture
    #[test]
    fn export_typescript() {
        let out_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
            .join("../../packages/ui/src/api-types.generated.ts");

        let cfg = ts_rs::Config::new().with_large_int("number");
        let mut parts: Vec<String> = Vec::new();
        parts.push("// AUTO-GENERATED by opensession-api-types — DO NOT EDIT".to_string());
        parts.push(
            "// Regenerate with: cargo test -p opensession-api-types -- export_typescript"
                .to_string(),
        );
        parts.push(String::new());

        // Collect all type declarations, converting `type X = {...}` to `export interface X {...}`
        macro_rules! collect_ts {
            ($($t:ty),+ $(,)?) => {
                $(
                    let decl = <$t>::decl(&cfg);
                    // Convert `type Foo = { ... };` to `export interface Foo { ... }`
                    let decl = decl
                        .replacen("type ", "export interface ", 1)
                        .replace(" = {", " {")
                        .trim_end_matches(';')
                        .to_string();
                    parts.push(decl);
                    parts.push(String::new());
                )+
            };
        }

        collect_ts!(
            // Auth
            RegisterRequest,
            AuthRegisterRequest,
            LoginRequest,
            AuthTokenResponse,
            RefreshRequest,
            LogoutRequest,
            ChangePasswordRequest,
            RegisterResponse,
            VerifyResponse,
            UserSettingsResponse,
            // Sessions
            UploadResponse,
            SessionSummary,
            SessionListResponse,
            SessionListQuery,
            SessionDetail,
            // Teams
            CreateTeamRequest,
            TeamResponse,
            ListTeamsResponse,
            TeamDetailResponse,
            UpdateTeamRequest,
            TeamStatsQuery,
            TeamStatsResponse,
            TeamStatsTotals,
            UserStats,
            ToolStats,
            // Members
            AddMemberRequest,
            MemberResponse,
            ListMembersResponse,
            // Invitations
            InviteRequest,
            InvitationResponse,
            ListInvitationsResponse,
            AcceptInvitationResponse,
            // Health
            HealthResponse,
            ApiError,
        );

        let content = parts.join("\n");

        // Write to file
        if let Some(parent) = out_dir.parent() {
            std::fs::create_dir_all(parent).ok();
        }
        let mut file = std::fs::File::create(&out_dir)
            .unwrap_or_else(|e| panic!("Failed to create {}: {}", out_dir.display(), e));
        file.write_all(content.as_bytes())
            .unwrap_or_else(|e| panic!("Failed to write {}: {}", out_dir.display(), e));

        println!("Generated TypeScript types at: {}", out_dir.display());
    }
}

//! Shared database schema and query definitions.
//! Used by: Axum server, Cloudflare Worker, TUI local DB.

use std::sync::LazyLock;

// ─── Schema ─────────────────────────────────────────────────────────────────

/// SQLite schema (compatible with D1). Does NOT include FTS5 (Axum-only).
pub const SCHEMA: &str = "\
CREATE TABLE IF NOT EXISTS users (
    id          TEXT PRIMARY KEY,
    nickname    TEXT NOT NULL UNIQUE,
    api_key     TEXT NOT NULL UNIQUE,
    is_admin    BOOLEAN NOT NULL DEFAULT 0,
    created_at  TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE IF NOT EXISTS teams (
    id          TEXT PRIMARY KEY,
    name        TEXT NOT NULL,
    description TEXT,
    is_public   BOOLEAN NOT NULL DEFAULT 0,
    created_by  TEXT NOT NULL,
    created_at  TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE IF NOT EXISTS team_members (
    team_id  TEXT NOT NULL,
    user_id  TEXT NOT NULL,
    role     TEXT NOT NULL DEFAULT 'member',
    joined_at TEXT NOT NULL DEFAULT (datetime('now')),
    PRIMARY KEY (team_id, user_id)
);
CREATE TABLE IF NOT EXISTS sessions (
    id                   TEXT PRIMARY KEY,
    user_id              TEXT,
    team_id              TEXT NOT NULL,
    tool                 TEXT NOT NULL,
    agent_provider       TEXT,
    agent_model          TEXT,
    title                TEXT,
    description          TEXT,
    tags                 TEXT,
    created_at           TEXT NOT NULL,
    uploaded_at          TEXT NOT NULL DEFAULT (datetime('now')),
    message_count        INTEGER DEFAULT 0,
    task_count           INTEGER DEFAULT 0,
    event_count          INTEGER DEFAULT 0,
    duration_seconds     INTEGER DEFAULT 0,
    total_input_tokens   INTEGER DEFAULT 0,
    total_output_tokens  INTEGER DEFAULT 0,
    body_storage_key     TEXT NOT NULL
);
";

/// Local-only SQLite schema for TUI + Daemon (not on the server).
pub const LOCAL_SCHEMA: &str = "\
CREATE TABLE IF NOT EXISTS local_sessions (
    id                   TEXT PRIMARY KEY,
    source_path          TEXT,
    sync_status          TEXT NOT NULL DEFAULT 'local_only',
    last_synced_at       TEXT,
    user_id              TEXT,
    nickname             TEXT,
    team_id              TEXT,
    tool                 TEXT NOT NULL,
    agent_provider       TEXT,
    agent_model          TEXT,
    title                TEXT,
    description          TEXT,
    tags                 TEXT,
    created_at           TEXT NOT NULL,
    uploaded_at          TEXT,
    message_count        INTEGER DEFAULT 0,
    task_count           INTEGER DEFAULT 0,
    event_count          INTEGER DEFAULT 0,
