/// Authenticated user extracted from the `Authorization: Bearer <api_key>` header.
pub struct AuthUser {
    pub user_id: String,
    pub nickname: String,
    pub is_admin: bool,
}

impl<S> FromRequestParts<S> for AuthUser
where
    S: Send + Sync,
    Db: axum::extract::FromRef<S>,
{
    type Rejection = ApiErr;

    async fn from_request_parts(parts: &mut Parts, state: &S) -> Result<Self, Self::Rejection> {
        let db = Db::from_ref(state);

        let api_key = parts
            .headers
            .get("authorization")
            .and_then(|v| v.to_str().ok())
            .and_then(|v| v.strip_prefix("Bearer "))
            .ok_or(ApiErr::unauthorized(
                "missing or invalid Authorization header",
            ))?
            .to_string();

        let conn = db.conn();
        conn.query_row(
            "SELECT id, nickname, is_admin FROM users WHERE api_key = ?1",
            [&api_key],
            |row| {
                Ok(AuthUser {
                    user_id: row.get(0)?,
                    nickname: row.get(1)?,
                    is_admin: row.get(2)?,
                })
            },
        )
        .map_err(|_| ApiErr::unauthorized("invalid API key"))
    }
}

