const USER_SELECT: &str = "\
    SELECT id, nickname, api_key, is_admin, created_at, \
    email, password_hash, password_salt, github_id, github_username, avatar_url \
    FROM users";

/// Look up a user by API key.
pub async fn authenticate(env: &Env, [REDACTED_CREDENTIAL] -> Result<Option<UserRow>> {
    let db = get_d1(env)?;
    let q = format!("{USER_SELECT} WHERE api_key = ?1");
    let stmt = db.prepare(&q);
    stmt.bind(&[api_key.into()])?.first::<UserRow>(None).await
}

/// Look up a user by id (for JWT-based auth).
pub async fn get_user_by_id(env: &Env, user_id: &str) -> Result<Option<UserRow>> {
    let db = get_d1(env)?;
