    let stmt = db.prepare(&q);
    stmt.bind(&[github_id.into()])?.first::<UserRow>(None).await
}

/// Extract the bearer token from an Authorization header value.
pub fn extract_bearer(auth_header: &str) -> Option<&str> {
    auth_header.trim().strip_prefix("Bearer ").map(|s| s.trim())
}

/// Extract JWT from cookie header. Looks for `session=<token>`.
fn extract_jwt_from_cookie(cookie_header: &str) -> Option<&str> {
    cookie_header.split(';').find_map(|part| {
        let part = part.trim();
        part.strip_prefix("session=")
    })
}

/// Get current unix timestamp via `Date.now()`.
pub fn now_unix() -> u64 {
    (chrono::Utc::now().timestamp()) as u64
}

/// Dual-auth middleware: JWT (cookie or header) → API key → 401.
///
/// Priority:
/// 1. `Cookie: session=<jwt>` or `Authorization: Bearer <jwt>` (non-osk_ prefix)
/// 2. `Authorization: Bearer osk_xxx` → API key DB lookup
/// 3. Both missing → 401
pub async fn auth_from_req(req: &Request, env: &Env) -> Result<UserRow> {
    let headers = req.headers();

    // Try JWT from cookie first
    if let Ok(Some(cookie)) = headers.get("Cookie") {
        if let Some(jwt) = extract_jwt_from_cookie(&cookie) {
            let secret = env
                .secret("JWT_SECRET")
                .map(|s| s.to_string())
                .map_err(|_| Error::from("JWT_SECRET not configured"))?;
            let user_id = crypto::verify_jwt(jwt, &secret, now_unix())?;
            return get_user_by_id(env, &user_id)
                .await?
                .ok_or_else(|| Error::from("User not found"));
        }
    }

    // Try Authorization header
    if let Ok(Some(auth)) = headers.get("Authorization") {
        let token = extract_bearer(&auth)
            .ok_or_else(|| Error::from("Invalid Authorization header"))?;

        // API key (osk_ prefix) → DB lookup
        if token.starts_with("osk_") {
            return authenticate(env, token)
                .await?
                .ok_or_else(|| Error::from("Unauthorized"));
        }

        // Otherwise treat as JWT
        let secret = env
            .secret("JWT_SECRET")
            .map(|s| s.to_string())
            .map_err(|_| Error::from("JWT_SECRET not configured"))?;
        let user_id = crypto::verify_jwt(token, &secret, now_unix())?;
        return get_user_by_id(env, &user_id)
            .await?
            .ok_or_else(|| Error::from("User not found"));
    }

    Err(Error::from("Unauthorized"))
}

/// Wrapper that returns a proper 401 response on auth failure.
pub async fn require_auth(req: &Request, env: &Env) -> std::result::Result<UserRow, Response> {
    auth_from_req(req, env).await.map_err(|e| {
        let msg = e.to_string();
        Response::error(&msg, 401).unwrap_or_else(|_| Response::error("Unauthorized", 401).unwrap())
    })
}

