/// Column list for invitation SELECT queries.
pub const INVITATION_COLUMNS: &str = "\
i.id, i.team_id, t.name AS team_name, i.email, i.github_username, \
u.nickname AS invited_by_nickname, i.role, i.status, i.created_at, i.expires_at";

/// INSERT a new invitation.
pub const INVITATION_INSERT: &str = "\
INSERT INTO team_invitations (id, team_id, email, github_username, invited_by, role, expires_at) \
VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7)";

/// List pending invitations for a user by email or github_username.
/// ?1 = email, ?2 = github_username
pub static INVITATION_LIST_MY: LazyLock<String> = LazyLock::new(|| {
    format!(
        "SELECT {INVITATION_COLUMNS} \
         FROM team_invitations i \
         INNER JOIN teams t ON t.id = i.team_id \
         INNER JOIN users u ON u.id = i.invited_by \
         WHERE i.status = 'pending' \
         AND i.expires_at > datetime('now') \
         AND ((i.email IS NOT NULL AND i.email = ?1) \
              OR (i.github_username IS NOT NULL AND i.github_username = ?2)) \
         ORDER BY i.created_at DESC"
    )
});

mod error;
mod routes;
mod storage;

use axum::{
    extract::{DefaultBodyLimit, FromRef},
    routing::{delete, get, post, put},
    Router,
};
use std::path::PathBuf;
use tower_http::cors::{Any, CorsLayer};
use tower_http::services::{ServeDir, ServeFile};
use tower_http::trace::TraceLayer;

use storage::Db;

/// Application state shared across all handlers.
#[derive(Clone)]
struct AppState {
    db: Db,
}

impl FromRef<AppState> for Db {
    fn from_ref(state: &AppState) -> Self {
        state.db.clone()
    }
}

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    // Initialize tracing
    tracing_subscriber::fmt()
        .with_env_filter(
            tracing_subscriber::EnvFilter::try_from_default_env()
                .unwrap_or_else(|_| "opensession_server=info,tower_http=info".into()),
        )
        .init();

    // Data directory
    let data_dir = std::env::var("OPENSESSION_DATA_DIR")
        .map(PathBuf::from)
        .unwrap_or_else(|_| PathBuf::from("data"));

    tracing::info!("data directory: {}", data_dir.display());

    // Initialize database
    let db = storage::init_db(&data_dir)?;
    tracing::info!("database initialized");

    let state = AppState { db };

    // Build API routes
    let api = Router::new()
        // Health
        .route("/health", get(routes::health::health))
        // Auth
        .route("/register", post(routes::[REDACTED_CREDENTIAL]
        .route("/auth/verify", post(routes::[REDACTED_CREDENTIAL]
        .route("/auth/me", get(routes::[REDACTED_CREDENTIAL]
        .route("/auth/regenerate-key", post(routes::[REDACTED_CREDENTIAL]
        // Sessions
        .route("/sessions", post(routes::sessions::upload_session))
        .layer(DefaultBodyLimit::max(256 * 1024 * 1024)) // 256MB for large sessions
        .route("/sessions", get(routes::sessions::list_sessions))
        .route("/sessions/{id}", get(routes::sessions::get_session))
        .route("/sessions/{id}/raw", get(routes::sessions::get_session_raw))
        // Teams
        .route("/teams", post(routes::teams::create_team))
        .route("/teams", get(routes::teams::list_my_teams))
        .route("/teams/{id}", get(routes::teams::get_team))
        .route("/teams/{id}", put(routes::teams::update_team))
        // Sync
        .route("/sync/pull", get(routes::sync::pull))
        // Team members
        .route("/teams/{id}/members", get(routes::teams::list_members))
        .route("/teams/{id}/members", post(routes::teams::add_member))
        .route(
            "/teams/{team_id}/members/{user_id}",
            delete(routes::teams::remove_member),
        );

    // Build main router
    let mut app = Router::new().nest("/api", api);

    // Serve static files from web build if present
    let web_dir = std::env::var("OPENSESSION_WEB_DIR")
        .map(PathBuf::from)
        .unwrap_or_else(|_| PathBuf::from("web/build"));
    if web_dir.exists() {
        tracing::info!("serving static files from {}", web_dir.display());
        let index_html = web_dir.join("index.html");
        app = app.fallback_service(ServeDir::new(&web_dir).fallback(ServeFile::new(index_html)));
    }

    let app = app
        .layer(TraceLayer::new_for_http())
        .layer(
            CorsLayer::new()
                .allow_origin(Any)
                .allow_methods(Any)
                .allow_headers(Any),
        )
        .with_state(state);

    let base_url =
        std::env::var("OPENSESSION_BASE_URL").unwrap_or_else(|_| "http://localhost:3000".into());
    tracing::info!("starting server at {base_url}");

    let port = std::env::var("PORT").unwrap_or_else(|_| "3000".into());
    let listener = tokio::net::TcpListener::bind(format!("0.0.0.0:{port}")).await?;
    axum::serve(listener, app).await?;

    Ok(())
}

use anyhow::{Context, Result};
use rusqlite::Connection;
use std::path::{Path, PathBuf};
use std::sync::{Arc, Mutex};

use opensession_api_types::{SessionSummary, TeamResponse};

/// Shared database state
#[derive(Clone)]
pub struct Db {
    conn: Arc<Mutex<Connection>>,
    data_dir: PathBuf,
}

impl Db {
    pub fn conn(&self) -> std::sync::MutexGuard<'_, Connection> {
        self.conn.lock().expect("database mutex poisoned")
    }

    /// Path to the session body storage directory
    pub fn bodies_dir(&self) -> PathBuf {
        self.data_dir.join("bodies")
    }

    /// Write a session body as HAIL JSONL to disk, return the storage key
    pub fn write_body(&self, session_id: &str, data: &[u8]) -> Result<String> {
        let dir = self.bodies_dir();
        std::fs::create_dir_all(&dir)?;
        let key = format!("{session_id}.hail.jsonl");
        let path = dir.join(&key);
        std::fs::write(&path, data).context("writing session body")?;
        Ok(key)
    }

    /// Read a session body from disk
    pub fn read_body(&self, storage_key: &str) -> Result<Vec<u8>> {
        let path = self.bodies_dir().join(storage_key);
        std::fs::read(&path).context("reading session body")
    }

    /// Check whether a user belongs to a team.
    pub fn is_team_member(&self, team_id: &str, user_id: &str) -> bool {
        self.conn()
            .query_row(
                "SELECT COUNT(*) > 0 FROM team_members WHERE team_id = ?1 AND user_id = ?2",
                rusqlite::params![team_id, user_id],
                |row| row.get(0),
            )
            .unwrap_or(false)
    }
}

/// Map a `SESSION_COLUMNS` row into a `SessionSummary`.
pub fn session_from_row(row: &rusqlite::Row<'_>) -> rusqlite::Result<SessionSummary> {
    Ok(SessionSummary {
        id: row.get(0)?,
        user_id: row.get(1)?,
        nickname: row.get(2)?,
        team_id: row.get(3)?,
        tool: row.get(4)?,
        agent_provider: row.get(5)?,
        agent_model: row.get(6)?,
        title: row.get(7)?,
        description: row.get(8)?,
