	const refreshToken = getRefreshToken();
	if (refreshToken) {
		try {
			await request('/api/auth/logout', {
				method: 'POST',
				body: JSON.stringify({ refresh_[REDACTED_CREDENTIAL] })
			});
		} catch {
			// Ignore errors during logout
		}
	}
	clearTokens();
	clearApiKey();
}

