   101→
   102→fn validate_email(email: &str) -> Result<String, ServiceError> {
   103→    let email = email.trim().to_lowercase();
   104→    if email.is_empty() || !email.contains('@') || email.len() > 254 {
   105→        return Err(ServiceError::BadRequest("invalid email address".into()));
   106→    }
   107→    Ok(email)
   108→}
   109→
   110→fn validate_password([REDACTED_CREDENTIAL] -> Result<(), ServiceError> {
   111→    if password.len() < 8 {
   112→        return Err(ServiceError::BadRequest(
   113→            "password must be at least 8 characters".into(),
   114→        ));
   115→    }
   116→    if password.len() > 12 {
   117→        return Err(ServiceError::BadRequest(
   118→            "password must be at most 12 characters".into(),
   119→        ));
   120→    }
   121→    Ok(())
   122→}
