   124→fn issue_tokens(
   125→    db: &Db,
   126→    jwt_[REDACTED_CREDENTIAL]
   127→    user_id: &str,
   128→    nickname: &str,
   129→) -> Result<AuthTokenResponse, ApiErr> {
   130→    let now = chrono::Utc::now().timestamp() as u64;
   131→    let access_token = crypto::sign_jwt(user_id, jwt_secret, now);
   132→
   133→    let refresh_token = crypto::generate_token();
   134→    let token_hash = crypto::hash_token(&refresh_token);
   135→    let token_id = Uuid::new_v4().to_string();
   136→    let expires_at = (chrono::Utc::now()
   137→        + chrono::Duration::seconds(crypto::REFRESH_EXPIRY_SECS as i64))
   138→    .format("%Y-%m-%d %H:%M:%S")
   139→    .to_string();
   140→
   141→    let conn = db.conn();
   142→    conn.execute(
   143→        "INSERT INTO refresh_tokens (id, user_id, token_hash, expires_at) VALUES (?1, ?2, ?3, ?4)",
   144→        rusqlite::params![token_id, user_id, token_hash, expires_at],
   145→    )
   146→    .map_err(ApiErr::from_db("issue_tokens"))?;
   147→
   148→    Ok(AuthTokenResponse {
   149→        access_token,
   150→        refresh_token,
   151→        expires_in: crypto::JWT_EXPIRY_SECS,
   152→        user_id: user_id.to_string(),
   153→        nickname: nickname.to_string(),
   154→    })
   155→}
