   157→fn is_first_user(db: &Db) -> bool {
   158→    let conn = db.conn();
   159→    let count: i64 = conn
   160→        .query_row("SELECT COUNT(*) FROM users", [], |row| row.get(0))
   161→        .unwrap_or(0);
   162→    count == 0
   163→}
