   178→    let conn = db.conn();
   179→
   180→    let user_count: i64 = conn
   181→        .query_row("SELECT COUNT(*) FROM users", [], |row| row.get(0))
   182→        .unwrap_or(0);
   183→    let is_admin = user_count == 0;
   184→
   185→    let result = conn.execute(
   186→        "INSERT INTO users (id, nickname, api_key, is_admin) VALUES (?1, ?2, ?3, ?4)",
   187→        rusqlite::params![&user_id, &nickname, &api_key, is_admin],
