   200→        Err(rusqlite::Error::SqliteFailure(err, _))
   201→            if err.code == rusqlite::ErrorCode::ConstraintViolation =>
   202→        {
   203→            Err(ApiErr::conflict("nickname already taken"))
   204→        }
   205→        Err(e) => {
