   216→/// POST /api/auth/register — email + password registration
   217→pub async fn auth_register(
   218→    State(db): State<Db>,
   219→    State(config): State<AppConfig>,
   220→    Json(req): Json<AuthRegisterRequest>,
   221→) -> Result<(StatusCode, Json<AuthTokenResponse>), ApiErr> {
   222→    if config.jwt_secret.is_empty() {
   223→        return Err(ApiErr::internal("JWT_SECRET not configured"));
   224→    }
   225→
   226→    let email = validate_email(&req.email).map_err(ApiErr::from)?;
   227→    validate_password(&req.password).map_err(ApiErr::from)?;
   228→    let nickname = service::validate_nickname(&req.nickname).map_err(ApiErr::from)?;
   229→
   230→    // Check email uniqueness
   231→    {
   232→        let conn = db.conn();
   233→        let exists: bool = conn
   234→            .query_row(
   235→                "SELECT COUNT(*) > 0 FROM users WHERE email = ?1",
   236→                [&email],
   237→                |row| row.get(0),
   238→            )
   239→            .unwrap_or(false);
   240→        if exists {
   241→            return Err(ApiErr::conflict("email already registered"));
   242→        }
   243→    }
   244→
   245→    let user_id = Uuid::new_v4().to_string();
   246→    let api_key = format!("osk_{}", Uuid::new_v4().simple());
   247→    let (password_hash, password_salt) = crypto::hash_password(&req.password);
   248→    let admin = is_first_user(&db);
   249→
   250→    {
   251→        let conn = db.conn();
   252→        let result = conn.execute(
   253→            "INSERT INTO users (id, nickname, api_key, is_admin, email, password_hash, password_salt) \
   254→             VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7)",
   255→            rusqlite::params![user_id, nickname, api_key, admin, email, password_hash, password_salt],
   256→        );
   257→        match result {
   258→            Ok(_) => {}
   259→            Err(rusqlite::Error::SqliteFailure(err, _))
   260→                if err.code == rusqlite::ErrorCode::ConstraintViolation =>
   261→            {
   262→                return Err(ApiErr::conflict("nickname already taken"));
   263→            }
