   275→/// POST /api/auth/login — email + password login
   276→pub async fn login(
   277→    State(db): State<Db>,
   278→    State(config): State<AppConfig>,
   279→    Json(req): Json<LoginRequest>,
   280→) -> Result<Json<AuthTokenResponse>, ApiErr> {
   281→    if config.jwt_secret.is_empty() {
   282→        return Err(ApiErr::internal("JWT_SECRET not configured"));
   283→    }
   284→
   285→    let email = validate_email(&req.email).map_err(ApiErr::from)?;
   286→
   287→    let conn = db.conn();
   288→    let user = conn
   289→        .query_row(
   290→            "SELECT id, nickname, password_hash, password_salt FROM users WHERE email = ?1",
   291→            [&email],
   292→            |row| {
   293→                Ok((
   294→                    row.get::<_, String>(0)?,
   295→                    row.get::<_, String>(1)?,
   296→                    row.get::<_, Option<String>>(2)?,
   297→                    row.get::<_, Option<String>>(3)?,
   298→                ))
   299→            },
   300→        )
   301→        .map_err(|_| ApiErr::unauthorized("invalid email or password"))?;
   302→
   303→    let (user_id, nickname, hash, salt) = user;
   304→    let (hash, salt) = match (hash, salt) {
   305→        (Some(h), Some(s)) => (h, s),
   306→        _ => {
   307→            return Err(ApiErr::unauthorized(
   308→                "this account uses OAuth login, not email/password",
   309→            ))
   310→        }
   311→    };
   312→
   313→    if !crypto::verify_password(&req.password, &hash, &salt) {
   314→        return Err(ApiErr::unauthorized("invalid email or password"));
   315→    }
   316→    drop(conn);
   317→
   318→    let tokens = issue_tokens(&db, &config.jwt_secret, &user_id, &nickname)?;
   319→    Ok(Json(tokens))
   320→}
