   322→/// POST /api/auth/refresh — exchange refresh token for new JWT
   323→pub async fn refresh(
   324→    State(db): State<Db>,
   325→    State(config): State<AppConfig>,
   326→    Json(req): Json<RefreshRequest>,
   327→) -> Result<Json<AuthTokenResponse>, ApiErr> {
   328→    if config.jwt_secret.is_empty() {
   329→        return Err(ApiErr::internal("JWT_SECRET not configured"));
   330→    }
   331→
   332→    let token_hash = crypto::hash_token(&req.refresh_token);
   333→
   334→    let conn = db.conn();
   335→    let row = conn
   336→        .query_row(
   337→            "SELECT rt.id, rt.user_id, rt.expires_at, u.nickname \
   338→             FROM refresh_tokens rt \
   339→             JOIN users u ON u.id = rt.user_id \
   340→             WHERE rt.token_hash = ?1",
   341→            [&token_hash],
   342→            |row| {
   343→                Ok((
   344→                    row.get::<_, String>(0)?,
   345→                    row.get::<_, String>(1)?,
   346→                    row.get::<_, String>(2)?,
   347→                    row.get::<_, String>(3)?,
   348→                ))
   349→            },
   350→        )
   351→        .map_err(|_| ApiErr::unauthorized("invalid refresh token"))?;
   352→
   353→    let (rt_id, user_id, expires_at, nickname) = row;
   354→
   355→    let now = chrono::Utc::now().format("%Y-%m-%d %H:%M:%S").to_string();
   356→    if expires_at < now {
   357→        conn.execute("DELETE FROM refresh_tokens WHERE id = ?1", [&rt_id])
   358→            .ok();
   359→        return Err(ApiErr::unauthorized("refresh token expired"));
   360→    }
   361→
   362→    // Rotate: delete old, issue new
   363→    conn.execute(
   364→        "DELETE FROM refresh_tokens WHERE token_hash = ?1",
   365→        [&token_hash],
   366→    )
   367→    .ok();
   368→    drop(conn);
   369→
   370→    let tokens = issue_tokens(&db, &config.jwt_secret, &user_id, &nickname)?;
   371→    Ok(Json(tokens))
   372→}
