// ── Helpers ─────────────────────────────────────────────────────────────────

/// Check if first user (for admin seeding).
async fn is_first_user(db: &D1Database) -> Result<bool> {
    let count_result = db
        .prepare("SELECT COUNT(*) as count FROM users")
        .all()
        .await?;
    let count = count_result
        .results::<storage::CountRow>()?
        .first()
        .map(|r| r.count)
        .unwrap_or(0);
    Ok(count == 0)
}

/// Create JWT + refresh token pair and store refresh token in D1.
async fn issue_tokens(
    env: &Env,
    user_id: &str,
    nickname: &str,
) -> Result<AuthTokenResponse> {
    let secret = env
        .secret("JWT_SECRET")
        .map(|s| s.to_string())
        .map_err(|_| Error::from("JWT_SECRET not configured"))?;

    let now = storage::now_unix();
    let access_token = crypto::sign_jwt(user_id, &secret, now);

    // Create refresh token
    let refresh_token = crypto::generate_token();
    let token_hash = crypto::hash_token(&refresh_token);
    let token_id = uuid::Uuid::new_v4().to_string();
    let expires_at = chrono::Utc::now()
        + chrono::Duration::seconds(crypto::REFRESH_EXPIRY_SECS as i64);
    let expires_at_str = expires_at.format("%Y-%m-%d %H:%M:%S").to_string();

    let db = storage::get_d1(env)?;
    db.prepare(
        "INSERT INTO refresh_tokens (id, user_id, token_hash, expires_at) VALUES (?1, ?2, ?3, ?4)",
    )
    .bind(&[
        token_id.into(),
        user_id.into(),
        token_hash.into(),
        expires_at_str.into(),
    ])?
    .run()
    .await?;

    Ok(AuthTokenResponse {
        access_token,
        refresh_token,
        expires_in: crypto::JWT_EXPIRY_SECS,
        user_id: user_id.to_string(),
        nickname: nickname.to_string(),
    })
}

fn validate_email(email: &str) -> std::result::Result<String, ServiceError> {
    let email = email.trim().to_lowercase();
    if email.is_empty() || !email.contains('@') || email.len() > 254 {
        return Err(ServiceError::BadRequest(
            "invalid email address".into(),
        ));
    }
    Ok(email)
}

fn validate_password([REDACTED_CREDENTIAL] -> std::result::Result<(), ServiceError> {
    if password.len() < 8 {
        return Err(ServiceError::BadRequest(
            "password must be at least 8 characters".into(),
        ));
    }
    if password.len() > 12 {
        return Err(ServiceError::BadRequest(
            "password must be at most 12 characters".into(),
        ));
    }
    Ok(())
}

// ── Legacy register (nickname only, for CLI) ────────────────────────────────

/// POST /api/register — first user becomes admin (legacy, CLI-compatible)
pub async fn register(mut req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let body: RegisterRequest = req.json().await?;

    let nickname = match service::validate_nickname(&body.nickname) {
        Ok(n) => n,
        Err(e) => return e.into_err_response(),
    };

    let user_id = uuid::Uuid::new_v4().to_string();
    let api_key = format!("osk_{}", uuid::Uuid::new_v4().simple());

    let db = storage::get_d1(&ctx.env)?;
    let is_admin = is_first_user(&db).await?;

    let result = db
        .prepare("INSERT INTO users (id, nickname, api_key, is_admin) VALUES (?1, ?2, ?3, ?4)")
        .bind(&[
            user_id.clone().into(),
            nickname.clone().into(),
            api_key.clone().into(),
            is_admin.into(),
        ])?
        .run()
        .await;

    match result {
        Ok(_) => {
            let mut resp = Response::from_json(&RegisterResponse {
                user_id,
                nickname,
                api_key,
                is_admin,
            })?;
            resp = resp.with_status(201);
            Ok(resp)
        }
        Err(e) => {
            let msg = e.to_string();
            if msg.contains("UNIQUE") || msg.contains("constraint") {
                ServiceError::Conflict("nickname already taken".into()).into_err_response()
            } else {
                ServiceError::Internal("internal server error".into()).into_err_response()
            }
        }
    }
}

// ── Email/password auth ─────────────────────────────────────────────────────

/// POST /api/auth/register — email + password registration
pub async fn auth_register(mut req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let body: AuthRegisterRequest = req.json().await?;

    let email = match validate_email(&body.email) {
        Ok(e) => e,
        Err(e) => return e.into_err_response(),
    };
    if let Err(e) = validate_password(&body.password) {
        return e.into_err_response();
    }
    let nickname = match service::validate_nickname(&body.nickname) {
        Ok(n) => n,
        Err(e) => return e.into_err_response(),
    };

    // Check email uniqueness
    if storage::get_user_by_email(&ctx.env, &email).await?.is_some() {
        return ServiceError::Conflict("email already registered".into()).into_err_response();
    }

    let user_id = uuid::Uuid::new_v4().to_string();
    let api_key = format!("osk_{}", uuid::Uuid::new_v4().simple());
    let (password_hash, password_salt) = crypto::hash_password(&body.password);

    let db = storage::get_d1(&ctx.env)?;
    let is_admin = is_first_user(&db).await?;

    let result = db
        .prepare(
            "INSERT INTO users (id, nickname, api_key, is_admin, email, password_hash, password_salt) \
             VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7)",
        )
        .bind(&[
            user_id.clone().into(),
            nickname.clone().into(),
            api_key.into(),
            is_admin.into(),
            email.into(),
            password_hash.into(),
            password_salt.into(),
        ])?
        .run()
        .await;

    match result {
        Ok(_) => {
            let tokens = issue_tokens(&ctx.env, &user_id, &nickname).await?;
            let mut resp = Response::from_json(&tokens)?;
            resp = resp.with_status(201);
            Ok(resp)
        }
        Err(e) => {
            let msg = e.to_string();
            if msg.contains("UNIQUE") || msg.contains("constraint") {
                ServiceError::Conflict("nickname already taken".into()).into_err_response()
            } else {
                ServiceError::Internal("internal server error".into()).into_err_response()
            }
        }
    }
}

/// POST /api/auth/login — email + password login
pub async fn login(mut req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let body: LoginRequest = req.json().await?;

    let email = match validate_email(&body.email) {
        Ok(e) => e,
        Err(e) => return e.into_err_response(),
    };

    let user = match storage::get_user_by_email(&ctx.env, &email).await? {
        Some(u) => u,
        None => {
            return ServiceError::Unauthorized("invalid email or password".into())
                .into_err_response()
        }
    };

    let (hash, salt) = match (&user.password_hash, &user.password_salt) {
        (Some(h), Some(s)) => (h.as_str(), s.as_str()),
        _ => {
            return ServiceError::Unauthorized(
                "this account uses GitHub login, not email/password".into(),
            )
            .into_err_response()
        }
    };

    if !crypto::verify_password(&body.password, hash, salt) {
        return ServiceError::Unauthorized("invalid email or password".into()).into_err_response();
    }

    let tokens = issue_tokens(&ctx.env, &user.id, &user.nickname).await?;
    Response::from_json(&tokens)
}

/// POST /api/auth/refresh — exchange refresh token for new JWT
pub async fn refresh(mut req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let body: RefreshRequest = req.json().await?;

    let token_hash = crypto::hash_token(&body.refresh_token);
    let db = storage::get_d1(&ctx.env)?;

    // Look up and validate refresh token
    let row = db
        .prepare(
            "SELECT rt.id, rt.user_id, rt.expires_at, u.nickname \
             FROM refresh_tokens rt \
             JOIN users u ON u.id = rt.user_id \
             WHERE rt.token_hash = ?1",
        )
        .bind(&[token_hash.clone().into()])?
        .first::<RefreshTokenRow>(None)
        .await?;

    let row = match row {
        Some(r) => r,
        None => {
            return ServiceError::Unauthorized("invalid refresh token".into()).into_err_response()
        }
    };

    // Check expiry
    let now = chrono::Utc::now().format("%Y-%m-%d %H:%M:%S").to_string();
    if row.expires_at < now {
        // Delete expired token
        db.prepare("DELETE FROM refresh_tokens WHERE id = ?1")
            .bind(&[row.id.into()])?
            .run()
            .await?;
        return ServiceError::Unauthorized("refresh token expired".into()).into_err_response();
    }

    // Rotate: delete old token, issue new pair
    db.prepare("DELETE FROM refresh_tokens WHERE token_hash = ?1")
        .bind(&[token_hash.into()])?
        .run()
        .await?;

    let tokens = issue_tokens(&ctx.env, &row.user_id, &row.nickname).await?;
    Response::from_json(&tokens)
}

/// POST /api/auth/logout — invalidate refresh token
pub async fn logout(mut req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let body: LogoutRequest = req.json().await?;

    let token_hash = crypto::hash_token(&body.refresh_token);
    let db = storage::get_d1(&ctx.env)?;

    db.prepare("DELETE FROM refresh_tokens WHERE token_hash = ?1")
        .bind(&[token_hash.into()])?
        .run()
        .await?;

    Response::from_json(&serde_json::json!({"ok": true}))
}

/// PUT /api/auth/password — change password (authenticated)
pub async fn change_password(mut req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let user = match storage::require_auth(&req, &ctx.env).await {
        Ok(u) => u,
        Err(resp) => return Ok(resp),
    };
    let body: ChangePasswordRequest = req.json().await?;

    // Must have existing password
    let (hash, salt) = match (&user.password_hash, &user.password_salt) {
        (Some(h), Some(s)) => (h.as_str(), s.as_str()),
        _ => {
            return ServiceError::BadRequest(
                "cannot change password for GitHub-only account".into(),
            )
            .into_err_response()
        }
    };

    if !crypto::verify_password(&body.current_password, hash, salt) {
        return ServiceError::Unauthorized("current password is incorrect".into())
            .into_err_response();
    }

    if let Err(e) = validate_password(&body.new_password) {
        return e.into_err_response();
    }

    let (new_hash, new_salt) = crypto::hash_password(&body.new_password);

    let db = storage::get_d1(&ctx.env)?;
    db.prepare("UPDATE users SET password_hash = ?1, password_salt = ?2 WHERE id = ?3")
        .bind(&[new_hash.into(), new_salt.into(), user.id.into()])?
        .run()
        .await?;

    Response::from_json(&serde_json::json!({"ok": true}))
}

// ── GitHub OAuth ────────────────────────────────────────────────────────────

/// GET /api/auth/github — redirect to GitHub OAuth authorization
pub async fn github_redirect(_req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let client_id = ctx
        .env
        .secret("GITHUB_CLIENT_ID")
        .map(|s| s.to_string())
        .map_err(|_| Error::from("GITHUB_CLIENT_ID not configured"))?;

    let base_url = ctx.env.var("BASE_URL")?.to_string();

    // Generate state parameter
    let state = crypto::generate_token();
    let expires_at = (chrono::Utc::now() + chrono::Duration::minutes(10))
        .format("%Y-%m-%d %H:%M:%S")
        .to_string();

    let db = storage::get_d1(&ctx.env)?;
    db.prepare("INSERT INTO oauth_states (state, expires_at, user_id) VALUES (?1, ?2, NULL)")
        .bind(&[state.clone().into(), expires_at.into()])?
        .run()
        .await?;

    let redirect_uri = format!("{base_url}/api/auth/github/callback");
    let url = format!(
        "https://github.com/login/oauth/authorize?client_id={}&redirect_uri={}&state={}&scope=read:user,user:email",
        client_id,
        urlencoding(&redirect_uri),
        state,
    );

    Response::redirect(Url::parse(&url)?)
}

/// GET /api/auth/github/callback — handle GitHub OAuth callback
pub async fn github_callback(req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let url = req.url()?;
    let params: std::collections::HashMap<String, String> =
        url.query_pairs().map(|(k, v)| (k.into_owned(), v.into_owned())).collect();

    let code = params
        .get("code")
        .ok_or_else(|| Error::from("missing code parameter"))?;
    let state = params
        .get("state")
        .ok_or_else(|| Error::from("missing state parameter"))?;

    // Validate state
    let db = storage::get_d1(&ctx.env)?;
    let state_row = db
        .prepare("SELECT state, expires_at, user_id FROM oauth_states WHERE state = ?1")
        .bind(&[state.clone().into()])?
        .first::<OAuthStateRow>(None)
        .await?;

    let linking_user_id = match state_row {
        None => return Response::error("invalid OAuth state", 400),
        Some(row) => {
            let now = chrono::Utc::now().format("%Y-%m-%d %H:%M:%S").to_string();
            if row.expires_at < now {
                return Response::error("OAuth state expired", 400);
            }
            // Delete used state
            db.prepare("DELETE FROM oauth_states WHERE state = ?1")
                .bind(&[state.clone().into()])?
                .run()
                .await?;
            row.user_id
        }
    };

    // Exchange code for access token
    let client_id = ctx.env.secret("GITHUB_CLIENT_ID")?.to_string();
    let client_secret = ctx.env.secret("GITHUB_CLIENT_SECRET")?.to_string();

    let mut token_resp = Fetch::Request(
        Request::new_with_init(
            "https://github.com/login/oauth/access_token",
            RequestInit::new()
                .with_method(Method::Post)
                .with_headers({
                    let h = Headers::new();
                    let _ = h.set("Accept", "application/json");
                    let _ = h.set("Content-Type", "application/json");
                    h
                })
                .with_body(Some(
                    serde_json::json!({
                        "client_id": client_id,
                        "client_secret": client_secret,
                        "code": code,
                    })
                    .to_string()
                    .into(),
                )),
        )?,
    )
    .send()
    .await?;

    let token_body: serde_json::Value = token_resp.json().await?;
    let gh_access_token = token_body["access_token"]
        .as_str()
        .ok_or_else(|| Error::from("GitHub OAuth failed: no access_token"))?;

    // Fetch GitHub user info
    let mut user_resp = Fetch::Request(
        Request::new_with_init(
            "https://api.github.com/user",
            RequestInit::new().with_headers({
                let h = Headers::new();
                let _ = h.set("Authorization", &format!("Bearer {gh_access_token}"));
                let _ = h.set("User-Agent", "opensession-worker");
                let _ = h.set("Accept", "application/json");
                h
            }),
        )?,
    )
    .send()
    .await?;

    let gh_user: serde_json::Value = user_resp.json().await?;
    let github_id = gh_user["id"].to_string();
    let github_username = gh_user["login"]
        .as_str()
        .unwrap_or("unknown")
        .to_string();
    let avatar_url = gh_user["avatar_url"].as_str().map(|s| s.to_string());

    // Fetch primary email
    let mut emails_resp = Fetch::Request(
        Request::new_with_init(
            "https://api.github.com/user/emails",
            RequestInit::new().with_headers({
                let h = Headers::new();
                let _ = h.set("Authorization", &format!("Bearer {gh_access_token}"));
                let _ = h.set("User-Agent", "opensession-worker");
                let _ = h.set("Accept", "application/json");
                h
            }),
        )?,
    )
    .send()
    .await?;

    let emails: Vec<serde_json::Value> = emails_resp.json().await?;
    let primary_email = emails
        .iter()
        .find(|e| e["primary"].as_bool() == Some(true))
        .and_then(|e| e["email"].as_str())
        .map(|s| s.to_string());

    // Find or create user
    let existing = storage::get_user_by_github_id(&ctx.env, &github_id).await?;
    let base_url = ctx.env.var("BASE_URL")?.to_string();

    // ── Linking mode: associate GitHub with existing account ──
    if let Some(ref link_uid) = linking_user_id {
        // Check if this GitHub ID is already linked to another account
        if let Some(ref existing_user) = existing {
            if existing_user.id != *link_uid {
                let redirect_url = format!("{base_url}/settings?error=github_already_linked");
                return Response::redirect(Url::parse(&redirect_url)?);
            }
        }

        // Link GitHub to the authenticated user
        db.prepare(
            "UPDATE users SET github_id = ?1, github_username = ?2, avatar_url = ?3 WHERE id = ?4",
        )
        .bind(&[
            github_id.into(),
            github_username.into(),
            avatar_url.unwrap_or_default().into(),
            link_uid.clone().into(),
        ])?
        .run()
        .await?;

        let redirect_url = format!("{base_url}/settings?github_linked=true");
        return Response::redirect(Url::parse(&redirect_url)?);
    }

    // ── Normal login/register flow ──
    let (user_id, nickname) = if let Some(user) = existing {
        // Update GitHub info
        db.prepare(
            "UPDATE users SET github_username = ?1, avatar_url = ?2 WHERE id = ?3",
        )
        .bind(&[
            github_username.clone().into(),
            avatar_url.clone().unwrap_or_default().into(),
            user.id.clone().into(),
        ])?
        .run()
        .await?;
        (user.id, user.nickname)
    } else {
        // Check if email already exists (link accounts)
        let by_email = if let Some(ref email) = primary_email {
            storage::get_user_by_email(&ctx.env, email).await?
        } else {
            None
        };

        if let Some(user) = by_email {
            // Link GitHub to existing email account
            db.prepare(
                "UPDATE users SET github_id = ?1, github_username = ?2, avatar_url = ?3 WHERE id = ?4",
            )
            .bind(&[
                github_id.clone().into(),
                github_username.clone().into(),
                avatar_url.clone().unwrap_or_default().into(),
                user.id.clone().into(),
            ])?
            .run()
            .await?;
            (user.id, user.nickname)
        } else {
            // Create new user
            let user_id = uuid::Uuid::new_v4().to_string();
            let api_key = format!("osk_{}", uuid::Uuid::new_v4().simple());
            let is_admin = is_first_user(&db).await?;

            db.prepare(
                "INSERT INTO users (id, nickname, api_key, is_admin, email, github_id, github_username, avatar_url) \
                 VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7, ?8)",
            )
            .bind(&[
                user_id.clone().into(),
                github_username.clone().into(),
                api_key.into(),
                is_admin.into(),
                primary_email.clone().unwrap_or_default().into(),
                github_id.into(),
                github_username.clone().into(),
                avatar_url.unwrap_or_default().into(),
            ])?
            .run()
            .await?;

            (user_id, github_username.clone())
        }
    };

    // Issue tokens
    let tokens = issue_tokens(&ctx.env, &user_id, &nickname).await?;

    // Redirect to frontend with tokens in URL fragment (not query params for security)
    let redirect_url = format!(
        "{base_url}/auth/callback#access_[REDACTED_CREDENTIAL]
        tokens.access_token, tokens.refresh_token, tokens.expires_in,
    );

    Response::redirect(Url::parse(&redirect_url)?)
}

// ── GitHub linking (from Settings) ──────────────────────────────────────────

/// POST /api/auth/github/link — initiate GitHub linking for authenticated user
pub async fn github_link(req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let user = match storage::require_auth(&req, &ctx.env).await {
        Ok(u) => u,
        Err(resp) => return Ok(resp),
    };

    // Already linked?
    if user.github_id.is_some() {
        return ServiceError::Conflict("GitHub account already linked".into()).into_err_response();
    }

    let client_id = ctx
        .env
        .secret("GITHUB_CLIENT_ID")
        .map(|s| s.to_string())
        .map_err(|_| Error::from("GITHUB_CLIENT_ID not configured"))?;
    let base_url = ctx.env.var("BASE_URL")?.to_string();

    // Generate state with user_id for linking
    let state = crypto::generate_token();
    let expires_at = (chrono::Utc::now() + chrono::Duration::minutes(10))
        .format("%Y-%m-%d %H:%M:%S")
        .to_string();

    let db = storage::get_d1(&ctx.env)?;
    db.prepare("INSERT INTO oauth_states (state, expires_at, user_id) VALUES (?1, ?2, ?3)")
        .bind(&[state.clone().into(), expires_at.into(), user.id.into()])?
        .run()
        .await?;

    let redirect_uri = format!("{base_url}/api/auth/github/callback");
    let url = format!(
        "https://github.com/login/oauth/authorize?client_id={}&redirect_uri={}&state={}&scope=read:user,user:email",
        client_id,
        urlencoding(&redirect_uri),
        state,
    );

    Response::from_json(&serde_json::json!({ "url": url }))
}

