/// GET /api/auth/me
pub async fn me(req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let user = match storage::auth_from_req(&req, &ctx.env).await {
        Ok(u) => u,
        Err(_) => return Response::error("Unauthorized", 401),
