            event_count: a.event_count as i64,
            tool_call_count: a.tool_call_count as i64,
            duration_seconds: a.duration_seconds as i64,
            total_input_tokens: a.total_input_tokens as i64,
            total_output_tokens: a.total_output_tokens as i64,
        }
    }
}

impl From<(String, opensession_core::stats::SessionAggregate)> for ToolStats {
