   708→
   709→    // Generate state with user_id for linking
   710→    let state = crypto::generate_token();
   711→    let expires_at = (chrono::Utc::now() + chrono::Duration::minutes(10))
   712→        .format("%Y-%m-%d %H:%M:%S")
   713→        .to_string();
   714→
   715→    db.prepare(dbq::OAUTH_STATE_INSERT)
   716→        .bind(&[
   717→            state.clone().into(),
   718→            provider_id.clone().into(),
   719→            expires_at.into(),
   720→            user.id.into(),
   721→        ])?
   722→        .run()
   723→        .await?;
