            if row.user_id != *link_uid {
                let redirect_url = format!("{base_url}/settings?error=oauth_already_linked");
                return Response::redirect(Url::parse(&redirect_url)?);
            }
        }

        db.prepare(dbq::OAUTH_IDENTITY_UPSERT)
            .bind(&[
                link_uid.clone().into(),
                provider_id.into(),
                user_info.provider_user_id.into(),
                user_info.username.into(),
                user_info.avatar_url.unwrap_or_default().into(),
                JsValue::NULL.into(),
            ])?
            .run()
            .await?;

        let redirect_url = format!("{base_url}/settings?oauth_linked=true");
        return Response::redirect(Url::parse(&redirect_url)?);
    }

    // ── Normal login/register flow ──

    // Check if OAuth identity already exists
    let existing: Option<OAuthIdentityRow> = db
        .prepare("SELECT user_id FROM oauth_identities WHERE provider = ?1 AND provider_user_id = ?2")
        .bind(&[provider_id.clone().into(), user_info.provider_user_id.clone().into()])?
        .first::<OAuthIdentityRow>(None)
        .await?;

    let (user_id, nickname) = if let Some(row) = existing {
        // Update provider info
        db.prepare(dbq::OAUTH_IDENTITY_UPSERT)
            .bind(&[
                row.user_id.clone().into(),
                provider_id.clone().into(),
                user_info.provider_user_id.clone().into(),
                user_info.username.clone().into(),
                user_info.avatar_url.clone().unwrap_or_default().into(),
                JsValue::NULL.into(),
            ])?
            .run()
            .await?;

        let nick: String = db
            .prepare("SELECT nickname FROM users WHERE id = ?1")
            .bind(&[row.user_id.clone().into()])?
            .first::<NicknameRow>(None)
            .await?
            .map(|r| r.nickname)
            .unwrap_or_else(|| user_info.username.clone());

        (row.user_id, nick)
    } else {
        // Check if email matches existing user (auto-link)
        let by_email = if let Some(ref email) = user_info.email {
            storage::get_user_by_email(&ctx.env, email).await?
        } else {
            None
        };

        if let Some(user) = by_email {
            db.prepare(dbq::OAUTH_IDENTITY_UPSERT)
                .bind(&[
                    user.id.clone().into(),
                    provider_id.clone().into(),
                    user_info.provider_user_id.clone().into(),
                    user_info.username.clone().into(),
                    user_info.avatar_url.clone().unwrap_or_default().into(),
                    JsValue::NULL.into(),
                ])?
                .run()
                .await?;
            (user.id, user.nickname)
        } else {
            // Create new user
            let user_id = uuid::Uuid::new_v4().to_string();
            let api_key = format!("osk_{}", uuid::Uuid::new_v4().simple());
            let is_admin = is_first_user(&db).await?;

            db.prepare(
                "INSERT INTO users (id, nickname, api_key, is_admin, email) \
                 VALUES (?1, ?2, ?3, ?4, ?5)",
            )
            .bind(&[
                user_id.clone().into(),
                user_info.username.clone().into(),
                api_key.into(),
                is_admin.into(),
                user_info.email.clone().unwrap_or_default().into(),
            ])?
            .run()
            .await?;

            db.prepare(dbq::OAUTH_IDENTITY_UPSERT)
                .bind(&[
                    user_id.clone().into(),
                    provider_id.into(),
                    user_info.provider_user_id.into(),
                    user_info.username.clone().into(),
                    user_info.avatar_url.unwrap_or_default().into(),
                    JsValue::NULL.into(),
                ])?
                .run()
                .await?;

            (user_id, user_info.username)
        }
    };

    // Issue tokens
    let tokens = issue_tokens(&ctx.env, &user_id, &nickname).await?;

    // Redirect to frontend with tokens in URL fragment (not query params for security)
    let redirect_url = format!(
        "{base_url}/auth/callback#access_[REDACTED_CREDENTIAL]
        tokens.access_token, tokens.refresh_token, tokens.expires_in,
    );

    Response::redirect(Url::parse(&redirect_url)?)
}

