}

export async function regenerateApiKey(): Promise<{ [REDACTED_CREDENTIAL] }> {
	return request('/api/auth/regenerate-key', {
		method: 'POST'
	});
}

// ── Auth (email/password + JWT) ─────────────────────────────────────────────

export async function authRegister(email: string, [REDACTED_CREDENTIAL] nickname: string): Promise<AuthTokenResponse> {
	const url = `${getBaseUrl()}/api/auth/register`;
	const res = await fetch(url, {
		method: 'POST',
		headers: { 'Content-Type': 'application/json' },
		body: JSON.stringify({ email, password, nickname })
	});
	if (!res.ok) {
		const body = await res.text();
		throw new ApiError(res.status, body);
	}
	const tokens: AuthTokenResponse = await res.json();
	storeTokens(tokens);
	return tokens;
}

export async function authLogin(email: string, [REDACTED_CREDENTIAL] Promise<AuthTokenResponse> {
	const url = `${getBaseUrl()}/api/auth/login`;
	const res = await fetch(url, {
		method: 'POST',
		headers: { 'Content-Type': 'application/json' },
		body: JSON.stringify({ email, password })
	});
	if (!res.ok) {
		const body = await res.text();
		throw new ApiError(res.status, body);
	}
	const tokens: AuthTokenResponse = await res.json();
	storeTokens(tokens);
	return tokens;
}

async function tryRefreshToken(): Promise<boolean> {
	const refreshToken = getRefreshToken();
	if (!refreshToken) return false;

	try {
		const url = `${getBaseUrl()}/api/auth/refresh`;
		const res = await fetch(url, {
			method: 'POST',
			headers: { 'Content-Type': 'application/json' },
			body: JSON.stringify({ refresh_[REDACTED_CREDENTIAL] })
		});
		if (!res.ok) return false;
		const tokens: AuthTokenResponse = await res.json();
		storeTokens(tokens);
		return true;
	} catch {
		return false;
	}
}

export async function authLogout(): Promise<void> {
	const refreshToken = getRefreshToken();
	if (refreshToken) {
		try {
			await request('/api/auth/logout', {
				method: 'POST',
				body: JSON.stringify({ refresh_[REDACTED_CREDENTIAL] })
			});
		} catch {
			// Ignore errors during logout
		}
	}
	clearTokens();
	clearApiKey();
}

export async function changePassword(current[REDACTED_CREDENTIAL] new[REDACTED_CREDENTIAL] Promise<void> {
	await request('/api/auth/password', {
		method: 'PUT',
		body: JSON.stringify({ current_[REDACTED_CREDENTIAL] new_[REDACTED_CREDENTIAL] })
	});
}

export function getGitHubAuthUrl(): string {
	return `${getBaseUrl()}/api/auth/github`;
}

/** Initiate GitHub linking for an authenticated user (from Settings). */
export async function linkGitHub(): Promise<void> {
	const resp = await request<{ url: string }>('/api/auth/github/link', { method: 'POST' });
	window.location.href = resp.url;
}

// ── Invitations ─────────────────────────────────────────────────────────────

export async function inviteMember(
	teamId: string,
	data: { email?: string; github_username?: string; role?: string }
): Promise<InvitationResponse> {
	return request(`/api/teams/${encodeURIComponent(teamId)}/invite`, {
		method: 'POST',
		body: JSON.stringify(data)
	});
}

export async function listInvitations(): Promise<ListInvitationsResponse> {
	return request('/api/invitations');
}

export async function acceptInvitation(id: string): Promise<AcceptInvitationResponse> {
	return request(`/api/invitations/${encodeURIComponent(id)}/accept`, {
		method: 'POST'
	});
}

export async function declineInvitation(id: string): Promise<void> {
	await request(`/api/invitations/${encodeURIComponent(id)}/decline`, {
		method: 'POST'
	});
}

/** Handle OAuth callback: parse tokens from URL fragment. */
export function handleAuthCallback(): AuthTokenResponse | null {
	if (typeof window === 'undefined') return null;

	const hash = window.location.hash.slice(1);
	if (!hash) return null;

	const params = new URLSearchParams(hash);
	const accessToken = params.get('access_token');
	const refreshToken = params.get('refresh_token');
	const expiresIn = params.get('expires_in');

	if (!accessToken || !refreshToken || !expiresIn) return null;

	const tokens: AuthTokenResponse = {
		access_[REDACTED_CREDENTIAL]
		refresh_[REDACTED_CREDENTIAL]
		expires_in: parseInt(expiresIn, 10),
		user_id: '',
		nickname: ''
	};

	storeTokens(tokens);
	// Clean up URL fragment
	window.history.replaceState(null, '', window.location.pathname);
	return tokens;
}

