fn load_oauth_providers() -> Vec<OAuthProviderConfig> {
    let mut providers = Vec::new();

    // GitHub: GITHUB_CLIENT_ID + GITHUB_CLIENT_SECRET
    if let (Ok(id), Ok(secret)) = (
        std::env::var("GITHUB_CLIENT_ID"),
        std::env::var("GITHUB_CLIENT_SECRET"),
    ) {
        if !id.is_empty() && !secret.is_empty() {
            tracing::info!("OAuth provider enabled: GitHub");
            providers.push(o[REDACTED_CREDENTIAL] secret));
        }
    }

    // GitLab: GITLAB_URL + GITLAB_CLIENT_ID + GITLAB_CLIENT_SECRET
    if let (Ok(url), Ok(id), Ok(secret)) = (
        std::env::var("GITLAB_URL"),
        std::env::var("GITLAB_CLIENT_ID"),
        std::env::var("GITLAB_CLIENT_SECRET"),
    ) {
        if !url.is_empty() && !id.is_empty() && !secret.is_empty() {
            let ext_url = std::env::var("GITLAB_EXTERNAL_URL").ok().filter(|s| !s.is_empty());
            tracing::info!("OAuth provider enabled: GitLab ({})", url);
            providers.push(o[REDACTED_CREDENTIAL] ext_url, id, secret));
        }
    }

    providers
}

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    // Initialize tracing
    tracing_subscriber::fmt()
        .with_env_filter(
            tracing_subscriber::EnvFilter::try_from_default_env()
                .unwrap_or_else(|_| "opensession_server=info,tower_http=info".into()),
        )
        .init();

    // Data directory
    let data_dir = std::env::var("OPENSESSION_DATA_DIR")
        .map(PathBuf::from)
        .unwrap_or_else(|_| PathBuf::from("data"));

    tracing::info!("data directory: {}", data_dir.display());

    // Initialize database
    let db = storage::init_db(&data_dir)?;
    tracing::info!("database initialized");

    let base_url =
        std::env::var("OPENSESSION_BASE_URL").unwrap_or_else(|_| "http://localhost:3000".into());

    let jwt_secret = std::env::var("JWT_SECRET").unwrap_or_default();
    if jwt_secret.is_empty() {
        tracing::warn!("JWT_SECRET not set — JWT auth and OAuth will be disabled");
    }

    let oauth_providers = load_oauth_providers();

    let config = AppConfig {
        base_url: base_url.clone(),
        jwt_secret,
        oauth_providers,
    };

    let state = AppState { db, config };

    // Build API routes
    let api = Router::new()
        // Health
        .route("/health", get(routes::health::health))
        // Auth (legacy)
        .route("/register", post(routes::[REDACTED_CREDENTIAL]
        .route("/auth/verify", post(routes::[REDACTED_CREDENTIAL]
        .route("/auth/me", get(routes::[REDACTED_CREDENTIAL]
        .route("/auth/regenerate-key", post(routes::[REDACTED_CREDENTIAL]
        // Auth (email/password + JWT)
        .route("/auth/register", post(routes::[REDACTED_CREDENTIAL]
        .route("/auth/login", post(routes::[REDACTED_CREDENTIAL]
        .route("/auth/refresh", post(routes::[REDACTED_CREDENTIAL]
        .route("/auth/logout", post(routes::[REDACTED_CREDENTIAL]
        .route("/auth/password", put(routes::[REDACTED_CREDENTIAL]
        // OAuth (generic — handles any provider)
        .route("/auth/providers", get(routes::o[REDACTED_CREDENTIAL]
        .route("/auth/oauth/{provider}", get(routes::o[REDACTED_CREDENTIAL]
        .route(
            "/auth/oauth/{provider}/callback",
            get(routes::o[REDACTED_CREDENTIAL]
        )
        .route(
            "/auth/oauth/{provider}/link",
            post(routes::o[REDACTED_CREDENTIAL]
        )
        // Sessions
        .route("/sessions", post(routes::sessions::upload_session))
        .layer(DefaultBodyLimit::max(256 * 1024 * 1024)) // 256MB for large sessions
        .route("/sessions", get(routes::sessions::list_sessions))
        .route("/sessions/{id}", get(routes::sessions::get_session))
        .route("/sessions/{id}/raw", get(routes::sessions::get_session_raw))
        // Teams
        .route("/teams", post(routes::teams::create_team))
        .route("/teams", get(routes::teams::list_my_teams))
        .route("/teams/{id}", get(routes::teams::get_team))
        .route("/teams/{id}", put(routes::teams::update_team))
        // Sync
        .route("/sync/pull", get(routes::sync::pull))
        // Team members
        .route("/teams/{id}/members", get(routes::teams::list_members))
        .route("/teams/{id}/members", post(routes::teams::add_member))
        .route(
            "/teams/{team_id}/members/{user_id}",
            delete(routes::teams::remove_member),
        );

    // Build main router
    let mut app = Router::new().nest("/api", api);

    // Serve static files from web build if present
    let web_dir = std::env::var("OPENSESSION_WEB_DIR")
        .map(PathBuf::from)
        .unwrap_or_else(|_| PathBuf::from("web/build"));
    if web_dir.exists() {
        tracing::info!("serving static files from {}", web_dir.display());
        let index_html = web_dir.join("index.html");
        app = app.fallback_service(ServeDir::new(&web_dir).fallback(ServeFile::new(index_html)));
    }

    let app = app
        .layer(TraceLayer::new_for_http())
        .layer(
            CorsLayer::new()
                .allow_origin(Any)
                .allow_methods(Any)
                .allow_headers(Any),
        )
        .with_state(state);

    tracing::info!("starting server at {base_url}");

    let port = std::env::var("PORT").unwrap_or_else(|_| "3000".into());
    let listener = tokio::net::TcpListener::bind(format!("0.0.0.0:{port}")).await?;
    axum::serve(listener, app).await?;

    Ok(())
}

