// ── OAuth inner implementations ─────────────────────────────────────────────

async fn oauth_redirect_inner(env: &Env, provider_id: &str) -> Result<Response> {
    let provider = load_provider_config(env, provider_id)?;
    let base_url = env.var("BASE_URL")?.to_string();

    let state = crypto::generate_token();
    let expires_at = (chrono::Utc::now() + chrono::Duration::minutes(10))
        .format("%Y-%m-%d %H:%M:%S")
        .to_string();

    let db = storage::get_d1(env)?;
    db.prepare(dbq::OAUTH_STATE_INSERT)
        .bind(&[
            state.clone().into(),
            provider_id.into(),
            expires_at.into(),
            JsValue::NULL.into(),
        ])?
        .run()
        .await?;

    let redirect_uri = format!("{base_url}/api/auth/oauth/{}/callback", provider.id);
    let url = o[REDACTED_CREDENTIAL] &redirect_uri, &state);
    Response::redirect(Url::parse(&url)?)
}

async fn oauth_callback_inner(
    req: Request,
    env: &Env,
    provider_id: &str,
) -> Result<Response> {
    let provider = load_provider_config(env, provider_id)?;

    let url = req.url()?;
    let params: std::collections::HashMap<String, String> = url
        .query_pairs()
        .map(|(k, v)| (k.into_owned(), v.into_owned()))
        .collect();

    let code = params
        .get("code")
        .ok_or_else(|| Error::from("missing code parameter"))?;
    let state_param = params
        .get("state")
        .ok_or_else(|| Error::from("missing state parameter"))?;

    // Validate state
    let db = storage::get_d1(env)?;
    let state_row = db
        .prepare(dbq::OAUTH_STATE_VALIDATE)
        .bind(&[state_param.clone().into()])?
        .first::<OAuthStateRow>(None)
        .await?;

    let linking_user_id = match state_row {
        None => return Response::error("invalid OAuth state", 400),
        Some(row) => {
            if row.provider != provider_id {
                return Response::error("OAuth state provider mismatch", 400);
            }
            let now = chrono::Utc::now()
                .format("%Y-%m-%d %H:%M:%S")
                .to_string();
            if row.expires_at < now {
                return Response::error("OAuth state expired", 400);
            }
            db.prepare(dbq::OAUTH_STATE_DELETE)
                .bind(&[state_param.clone().into()])?
                .run()
                .await?;
            row.user_id
        }
    };

    // Exchange code for access token
    let base_url = env.var("BASE_URL")?.to_string();
    let redirect_uri = format!("{base_url}/api/auth/oauth/{provider_id}/callback");
    let token_body = o[REDACTED_CREDENTIAL] code, &redirect_uri);

    let mut token_resp = Fetch::Request(Request::new_with_init(
        &provider.token_url,
        RequestInit::new()
            .with_method(Method::Post)
            .with_headers({
                let h = Headers::new();
                let _ = h.set("Accept", "application/json");
                let _ = h.set("Content-Type", "application/json");
                h
            })
            .with_body(Some(token_body.to_string().into())),
    )?)
    .send()
    .await?;

    let token_json: serde_json::Value = token_resp.json().await?;
    let access_token = token_json["access_token"]
        .as_str()
        .ok_or_else(|| Error::from("OAuth token exchange failed: no access_token"))?;

    // Fetch userinfo
    let mut userinfo_resp = Fetch::Request(Request::new_with_init(
        &provider.userinfo_url,
        RequestInit::new().with_headers({
            let h = Headers::new();
            let _ = h.set("Authorization", &format!("Bearer {access_token}"));
            let _ = h.set("User-Agent", "opensession-worker");
            let _ = h.set("Accept", "application/json");
            h
        }),
    )?)
    .send()
    .await?;

    let userinfo: serde_json::Value = userinfo_resp.json().await?;

    // Fetch emails if separate endpoint configured (GitHub)
    let emails: Option<Vec<serde_json::Value>> = match provider.email_url {
        Some(ref email_url) => {
            let mut resp = Fetch::Request(Request::new_with_init(
                email_url,
                RequestInit::new().with_headers({
                    let h = Headers::new();
                    let _ = h.set("Authorization", &format!("Bearer {access_token}"));
                    let _ = h.set("User-Agent", "opensession-worker");
                    let _ = h.set("Accept", "application/json");
                    h
                }),
            )?)
            .send()
            .await?;
            resp.json().await.ok()
        }
        None => None,
    };

    let user_info = match o[REDACTED_CREDENTIAL] &userinfo, emails.as_deref()) {
        Ok(info) => info,
        Err(e) => return e.into_err_response(),
    };

    // ── Linking mode ──
    if let Some(ref link_uid) = linking_user_id {
        let existing: Option<OAuthIdentityRow> = db
            .prepare(
                "SELECT user_id FROM oauth_identities \
                 WHERE provider = ?1 AND provider_user_id = ?2",
            )
            .bind(&[
                provider_id.into(),
                user_info.provider_user_id.clone().into(),
            ])?
            .first::<OAuthIdentityRow>(None)
            .await?;

        if let Some(ref row) = existing {
            if row.user_id != *link_uid {
                let redirect_url =
                    format!("{base_url}/settings?error=oauth_already_linked");
                return Response::redirect(Url::parse(&redirect_url)?);
            }
        }

        db.prepare(dbq::OAUTH_IDENTITY_UPSERT)
            .bind(&[
                link_uid.clone().into(),
                provider_id.into(),
                user_info.provider_user_id.into(),
                user_info.username.into(),
                user_info.avatar_url.unwrap_or_default().into(),
                JsValue::NULL.into(),
            ])?
            .run()
            .await?;

        let redirect_url = format!("{base_url}/settings?oauth_linked=true");
        return Response::redirect(Url::parse(&redirect_url)?);
    }

    // ── Normal login/register flow ──
    let existing: Option<OAuthIdentityRow> = db
        .prepare(
            "SELECT user_id FROM oauth_identities \
             WHERE provider = ?1 AND provider_user_id = ?2",
        )
        .bind(&[
            provider_id.into(),
            user_info.provider_user_id.clone().into(),
        ])?
        .first::<OAuthIdentityRow>(None)
        .await?;

    let (user_id, nickname) = if let Some(row) = existing {
        // Update provider info
        db.prepare(dbq::OAUTH_IDENTITY_UPSERT)
            .bind(&[
                row.user_id.clone().into(),
                provider_id.into(),
                user_info.provider_user_id.clone().into(),
                user_info.username.clone().into(),
                user_info.avatar_url.clone().unwrap_or_default().into(),
                JsValue::NULL.into(),
            ])?
            .run()
            .await?;

        let nick = db
            .prepare("SELECT nickname FROM users WHERE id = ?1")
            .bind(&[row.user_id.clone().into()])?
            .first::<NicknameRow>(None)
            .await?
            .map(|r| r.nickname)
            .unwrap_or_else(|| user_info.username.clone());

        (row.user_id, nick)
    } else {
        // Check if email matches existing user (auto-link)
        let by_email = if let Some(ref email) = user_info.email {
            storage::get_user_by_email(env, email).await?
        } else {
            None
        };

        if let Some(user) = by_email {
            db.prepare(dbq::OAUTH_IDENTITY_UPSERT)
                .bind(&[
                    user.id.clone().into(),
                    provider_id.into(),
                    user_info.provider_user_id.clone().into(),
                    user_info.username.clone().into(),
                    user_info.avatar_url.clone().unwrap_or_default().into(),
                    JsValue::NULL.into(),
                ])?
                .run()
                .await?;
            (user.id, user.nickname)
        } else {
            // Create new user
            let new_id = uuid::Uuid::new_v4().to_string();
            let api_key = format!("osk_{}", uuid::Uuid::new_v4().simple());
            let is_admin = is_first_user(&db).await?;

            db.prepare(
                "INSERT INTO users (id, nickname, api_key, is_admin, email) \
                 VALUES (?1, ?2, ?3, ?4, ?5)",
            )
            .bind(&[
                new_id.clone().into(),
                user_info.username.clone().into(),
                api_key.into(),
                is_admin.into(),
                user_info.email.clone().unwrap_or_default().into(),
            ])?
            .run()
            .await?;

            db.prepare(dbq::OAUTH_IDENTITY_UPSERT)
                .bind(&[
                    new_id.clone().into(),
                    provider_id.into(),
                    user_info.provider_user_id.into(),
                    user_info.username.clone().into(),
                    user_info.avatar_url.unwrap_or_default().into(),
                    JsValue::NULL.into(),
                ])?
                .run()
                .await?;

            (new_id, user_info.username)
        }
    };

    let tokens = issue_tokens(env, &user_id, &nickname).await?;

    let redirect_url = format!(
        "{base_url}/auth/callback#access_[REDACTED_CREDENTIAL]
        tokens.access_token, tokens.refresh_token, tokens.expires_in,
    );
    Response::redirect(Url::parse(&redirect_url)?)
}

async fn oauth_link_inner(req: Request, env: &Env, provider_id: &str) -> Result<Response> {
    let provider = load_provider_config(env, provider_id)?;

    let user = match storage::require_auth(&req, env).await {
        Ok(u) => u,
        Err(resp) => return Ok(resp),
    };

    let db = storage::get_d1(env)?;
    let already: Option<OAuthIdentityRow> = db
        .prepare("SELECT user_id FROM oauth_identities WHERE user_id = ?1 AND provider = ?2")
        .bind(&[user.id.clone().into(), provider_id.into()])?
        .first::<OAuthIdentityRow>(None)
        .await?;

    if already.is_some() {
        return ServiceError::Conflict(format!(
            "{} account already linked",
            provider.display_name
        ))
        .into_err_response();
    }

    let base_url = env.var("BASE_URL")?.to_string();
    let state = crypto::generate_token();
    let expires_at = (chrono::Utc::now() + chrono::Duration::minutes(10))
        .format("%Y-%m-%d %H:%M:%S")
        .to_string();

    db.prepare(dbq::OAUTH_STATE_INSERT)
        .bind(&[
            state.clone().into(),
            provider_id.into(),
            expires_at.into(),
            user.id.into(),
        ])?
        .run()
        .await?;

    let redirect_uri = format!("{base_url}/api/auth/oauth/{provider_id}/callback");
    let url = o[REDACTED_CREDENTIAL] &redirect_uri, &state);
    Response::from_json(&serde_json::json!({ "url": url }))
}

