/// GET /api/teams/:id — get team detail + sessions
pub async fn get(_req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let id = ctx.param("id").ok_or_else(|| Error::from("Missing id"))?;

    let d1 = storage::get_d1(&ctx.env)?;

    let team = d1
        .prepare(&*db::TEAM_GET)
        .bind(&[id.clone().into()])?
        .first::<storage::TeamRow>(None)
        .await?;

    let team = match team {
        Some(t) => TeamResponse::from(t),
        None => {
            return ServiceError::NotFound("team not found".into()).into_err_response();
        }
    };

    let member_count = d1
        .prepare("SELECT COUNT(*) as count FROM team_members WHERE team_id = ?1")
        .bind(&[id.clone().into()])?
        .first::<storage::CountRow>(None)
        .await?
        .map(|r| r.count)
        .unwrap_or(0);

    let select_sql = format!(
        "SELECT {} \
         FROM sessions s \
         LEFT JOIN users u ON u.id = s.user_id \
         WHERE s.team_id = ?1 \
         ORDER BY s.uploaded_at DESC \
         LIMIT 50",
        db::SESSION_COLUMNS,
    );

    let sessions_result = d1
        .prepare(&select_sql)
        .bind(&[id.clone().into()])?
        .all()
        .await?;

    let sessions: Vec<SessionSummary> = sessions_result
        .results::<storage::SessionRow>()?
        .into_iter()
        .map(SessionSummary::from)
        .collect();

    Response::from_json(&TeamDetailResponse {
        team,
        member_count,
        sessions,
    })
}

/// PUT /api/teams/:id — update team (site admin or team admin)
pub async fn update(mut req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let user = match storage::require_auth(&req, &ctx.env).await {
        Ok(u) => u,
        Err(resp) => return Ok(resp),
    };

    let id = ctx.param("id").ok_or_else(|| Error::from("Missing id"))?;

    let d1 = storage::get_d1(&ctx.env)?;

    if !user.is_admin && !is_team_admin(&d1, id, &user.id).await? {
        return ServiceError::Forbidden("admin only".into()).into_err_response();
    }

    let body: UpdateTeamRequest = req.json().await?;

    // Verify team exists
    let exists = d1
        .prepare("SELECT COUNT(*) as count FROM teams WHERE id = ?1")
        .bind(&[id.clone().into()])?
        .first::<storage::CountRow>(None)
        .await?
        .map(|r| r.count)
        .unwrap_or(0);

    if exists == 0 {
        return ServiceError::NotFound("team not found".into()).into_err_response();
    }

    if let Some(ref name) = body.name {
        let name = match service::validate_team_name(name) {
            Ok(n) => n,
            Err(e) => return e.into_err_response(),
        };
        d1.prepare("UPDATE teams SET name = ?1 WHERE id = ?2")
            .bind(&[name.into(), id.clone().into()])?
            .run()
            .await?;
    }

    if let Some(ref desc) = body.description {
        d1.prepare("UPDATE teams SET description = ?1 WHERE id = ?2")
            .bind(&[desc.clone().into(), id.clone().into()])?
            .run()
            .await?;
    }

    if let Some(is_public) = body.is_public {
        d1.prepare("UPDATE teams SET is_public = ?1 WHERE id = ?2")
            .bind(&[is_public.into(), id.clone().into()])?
            .run()
            .await?;
    }

    let team = d1
        .prepare(&*db::TEAM_GET)
        .bind(&[id.clone().into()])?
        .first::<storage::TeamRow>(None)
        .await?
        .ok_or_else(|| Error::from("team not found"))?;

    Response::from_json(&TeamResponse::from(team))
}

