/// POST /api/teams/:id/members — add member (site admin or team admin, by nickname)
pub async fn add_member(mut req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let user = match storage::require_auth(&req, &ctx.env).await {
        Ok(u) => u,
        Err(resp) => return Ok(resp),
    };

    let team_id = ctx.param("id").ok_or_else(|| Error::from("Missing id"))?;

    let d1 = storage::get_d1(&ctx.env)?;

    if !user.is_admin && !is_team_admin(&d1, team_id, &user.id).await? {
        return ServiceError::Forbidden("admin only".into()).into_err_response();
    }

    let body: AddMemberRequest = req.json().await?;

    // Look up user by nickname
    #[derive(Deserialize)]
    struct UserIdRow {
        id: String,
    }

    let target = d1
        .prepare("SELECT id FROM users WHERE nickname = ?1")
        .bind(&[body.nickname.clone().into()])?
        .first::<UserIdRow>(None)
        .await?;

    let target_id = match target {
        Some(u) => u.id,
        None => {
            return ServiceError::NotFound("user not found".into()).into_err_response();
        }
    };

    // Check not already a member
    let already = d1
        .prepare("SELECT COUNT(*) as count FROM team_members WHERE team_id = ?1 AND user_id = ?2")
        .bind(&[team_id.clone().into(), target_id.clone().into()])?
        .first::<storage::CountRow>(None)
        .await?
        .map(|r| r.count)
        .unwrap_or(0);

    if already > 0 {
        return ServiceError::Conflict("already a member".into()).into_err_response();
    }

    d1.prepare(db::MEMBER_INSERT)
        .bind(&[
            team_id.clone().into(),
            target_id.clone().into(),
            "member".into(),
        ])?
        .run()
        .await?;

    #[derive(Deserialize)]
    struct JoinedAtRow {
        joined_at: String,
    }

    let joined_at = d1
        .prepare("SELECT joined_at FROM team_members WHERE team_id = ?1 AND user_id = ?2")
        .bind(&[team_id.clone().into(), target_id.clone().into()])?
        .first::<JoinedAtRow>(None)
        .await?
        .map(|r| r.joined_at)
        .unwrap_or_default();

    let mut resp = Response::from_json(&MemberResponse {
        user_id: target_id,
        nickname: body.nickname,
        role: "member".to_string(),
        joined_at,
    })?;
    resp = resp.with_status(201);
    Ok(resp)
}

/// DELETE /api/teams/:team_id/members/:user_id — remove member (site admin or team admin)
pub async fn remove_member(req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let user = match storage::require_auth(&req, &ctx.env).await {
        Ok(u) => u,
        Err(resp) => return Ok(resp),
    };

    let team_id = ctx
        .param("team_id")
        .ok_or_else(|| Error::from("Missing team_id"))?;
    let user_id = ctx
        .param("user_id")
        .ok_or_else(|| Error::from("Missing user_id"))?;

    let d1 = storage::get_d1(&ctx.env)?;

    if !user.is_admin && !is_team_admin(&d1, team_id, &user.id).await? {
        return ServiceError::Forbidden("admin only".into()).into_err_response();
    }

    // D1 doesn't return affected rows directly, check existence first
    let exists = d1
        .prepare("SELECT COUNT(*) as count FROM team_members WHERE team_id = ?1 AND user_id = ?2")
        .bind(&[team_id.clone().into(), user_id.clone().into()])?
        .first::<storage::CountRow>(None)
        .await?
        .map(|r| r.count)
        .unwrap_or(0);

    if exists == 0 {
        return ServiceError::NotFound("member not found".into()).into_err_response();
    }

    d1.prepare(db::MEMBER_DELETE)
        .bind(&[team_id.clone().into(), user_id.clone().into()])?
        .run()
        .await?;

    Ok(Response::empty()?.with_status(204))
}

