/// POST /api/teams/:id/invite — invite member by email or GitHub username
pub async fn invite_member(mut req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let user = match storage::require_auth(&req, &ctx.env).await {
        Ok(u) => u,
        Err(resp) => return Ok(resp),
    };

    let team_id = ctx.param("id").ok_or_else(|| Error::from("Missing id"))?;
    let d1 = storage::get_d1(&ctx.env)?;

    if !user.is_admin && !is_team_admin(&d1, team_id, &user.id).await? {
        return ServiceError::Forbidden("team admin only".into()).into_err_response();
    }

    let body: InviteRequest = req.json().await?;

    let email = body.email.as_deref().map(|e| e.trim().to_lowercase());
    let github_username = body.github_username.as_deref().map(|g| g.trim().to_string());
    let role = body.role.as_deref().unwrap_or("member");

    if email.is_none() && github_username.is_none() {
        return ServiceError::BadRequest("email or github_username required".into())
            .into_err_response();
    }

    // Check for duplicate pending invitation
    let dup_check = if let Some(ref email) = email {
        d1.prepare(
            "SELECT COUNT(*) as count FROM team_invitations \
             WHERE team_id = ?1 AND email = ?2 AND status = 'pending'",
        )
        .bind(&[team_id.clone().into(), email.clone().into()])?
        .first::<storage::CountRow>(None)
        .await?
    } else if let Some(ref gh) = github_username {
        d1.prepare(
            "SELECT COUNT(*) as count FROM team_invitations \
             WHERE team_id = ?1 AND github_username = ?2 AND status = 'pending'",
        )
        .bind(&[team_id.clone().into(), gh.clone().into()])?
        .first::<storage::CountRow>(None)
        .await?
    } else {
        None
    };

    if dup_check.map(|r| r.count).unwrap_or(0) > 0 {
        return ServiceError::Conflict("invitation already pending".into()).into_err_response();
    }

    let id = uuid::Uuid::new_v4().to_string();
    let expires_at = (chrono::Utc::now() + chrono::Duration::days(7))
        .format("%Y-%m-%d %H:%M:%S")
        .to_string();

    let email_val: wasm_bindgen::JsValue = match &email {
        Some(e) => e.clone().into(),
        None => wasm_bindgen::JsValue::NULL,
    };
    let gh_val: wasm_bindgen::JsValue = match &github_username {
        Some(g) => g.clone().into(),
        None => wasm_bindgen::JsValue::NULL,
    };

    d1.prepare(db::INVITATION_INSERT)
        .bind(&[
            id.clone().into(),
            team_id.clone().into(),
            email_val,
            gh_val,
            user.id.clone().into(),
            role.into(),
            expires_at.into(),
        ])?
        .run()
        .await?;

    // Fetch team name for the response
    let team_name = d1
        .prepare("SELECT name FROM teams WHERE id = ?1")
        .bind(&[team_id.clone().into()])?
        .first::<TeamNameRow>(None)
        .await?
        .map(|r| r.name)
        .unwrap_or_default();

    let mut resp = Response::from_json(&InvitationResponse {
        id,
        team_id: team_id.to_string(),
        team_name,
        email,
        github_username,
        invited_by_nickname: user.nickname,
        role: role.to_string(),
        status: "pending".to_string(),
        created_at: chrono::Utc::now()
            .format("%Y-%m-%d %H:%M:%S")
            .to_string(),
    })?;
    resp = resp.with_status(201);
    Ok(resp)
}

