/// POST /api/sessions — upload a new session
pub async fn create(mut req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let user = match storage::require_auth(&req, &ctx.env).await {
        Ok(u) => u,
        Err(resp) => return Ok(resp),
    };

    let body: serde_json::Value = req.json().await?;

    let session_value = body
        .get("session")
        .ok_or_else(|| Error::from("missing 'session' field"))?;

    // team_id is optional: absent or null → "personal"
    let team_id = body
        .get("team_id")
        .and_then(|v| v.as_str())
        .unwrap_or("personal")
        .to_string();

    // body_url: external storage link (git repo, etc.)
    let body_url = body
        .get("body_url")
        .and_then(|v| v.as_str())
        .map(String::from);

    let d1 = storage::get_d1(&ctx.env)?;

    // Verify team membership (skip for personal sessions)
    if team_id != "personal" {
        let member_check = d1
            .prepare(
                "SELECT COUNT(*) as count FROM team_members WHERE team_id = ?1 AND user_id = ?2",
            )
            .bind(&[team_id.clone().into(), user.id.clone().into()])?
            .first::<storage::CountRow>(None)
            .await?;

        if member_check.map(|r| r.count).unwrap_or(0) == 0 {
            return ServiceError::Forbidden("not a member of this team".into()).into_err_response();
        }
    }

    // Parse the session using opensession-core
    let session: opensession_core::Session = serde_json::from_value(session_value.clone())
        .map_err(|e| Error::from(format!("Invalid session: {e}")))?;

    // Serialize body to HAIL JSONL
    let body_jsonl = session
        .to_jsonl()
        .map_err(|e| Error::from(format!("Failed to serialize session: {e}")))?;

    let session_id = uuid::Uuid::new_v4().to_string();
    let storage_key = format!("{session_id}.hail.jsonl");

    // Store full body in R2 only if no external body_url is provided
    if body_url.is_none() {
        storage::put_session_body(&ctx.env, &storage_key, body_jsonl.as_bytes()).await?;
    }

    let meta = opensession_core::extract::extract_upload_metadata(&session);

    // If body_url is provided, use empty storage key (body is external)
    let effective_storage_key = if body_url.is_some() {
        String::new()
    } else {
        storage_key
    };

    // body_url as JsValue (null if None)
    let body_url_val: worker::wasm_bindgen::JsValue = match &body_url {
        Some(url) => url.clone().into(),
        None => worker::wasm_bindgen::JsValue::NULL,
    };

    // Store metadata in D1 using shared INSERT query (18 params)
    d1.prepare(db::SESSION_INSERT)
        .bind(&[
            session_id.clone().into(),
            user.id.into(),
            team_id.into(),
            session.agent.tool.into(),
            session.agent.provider.into(),
            session.agent.model.into(),
            meta.title.unwrap_or_default().into(),
            meta.description.unwrap_or_default().into(),
            meta.tags.unwrap_or_default().into(),
            meta.created_at.into(),
            (session.stats.message_count as f64).into(),
            (session.stats.task_count as f64).into(),
            (session.stats.event_count as f64).into(),
            (session.stats.duration_seconds as f64).into(),
            (session.stats.total_input_tokens as f64).into(),
            (session.stats.total_output_tokens as f64).into(),
            effective_storage_key.into(),
            body_url_val,
        ])?
        .run()
        .await?;

    // Insert session links: prefer explicit linked_session_ids, fall back to context.related_session_ids
    let explicit_links: Vec<String> = body
        .get("linked_session_ids")
        .and_then(|v| v.as_array())
        .map(|arr| {
            arr.iter()
                .filter_map(|v| v.as_str().map(String::from))
                .collect()
        })
        .unwrap_or_default();

    let mut linked_ids: std::collections::HashSet<String> = explicit_links.into_iter().collect();
    for id in &session.context.related_session_ids {
        linked_ids.insert(id.clone());
    }

    for linked_id in &linked_ids {
        let _ = d1
            .prepare(db::SESSION_LINK_INSERT)
            .bind(&[
                session_id.clone().into(),
                linked_id.clone().into(),
                "handoff".into(),
            ])?
            .run()
            .await;
    }

    let base_url = ctx
        .env
        .var("BASE_URL")
        .map(|v| v.to_string())
        .unwrap_or_else(|_| "https://opensession.io".to_string());
    let url = format!("{base_url}/session/{session_id}");

    let mut resp = Response::from_json(&UploadResponse {
        id: session_id,
        url,
    })?;
    resp = resp.with_status(201);
    Ok(resp)
}

/// Convert shared [`ParamValue`] to D1 JsValue bind params.
fn to_d1_params(params: &[ParamValue]) -> Vec<worker::wasm_bindgen::JsValue> {
    params
        .iter()
        .map(|p| match p {
            ParamValue::Text(s) => s.clone().into(),
            ParamValue::Int(n) => (*n as f64).into(),
        })
        .collect()
}

/// GET /api/sessions — list sessions (public, paginated, filtered)
pub async fn list(req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let url = req.url()?;
    let query_pairs: Vec<(String, String)> = url.query_pairs().into_owned().collect();

    let q = SessionListQuery {
        page: query_pairs
            .iter()
            .find(|(k, _)| k == "page")
            .and_then(|(_, v)| v.parse().ok())
            .unwrap_or(1),
        per_page: query_pairs
            .iter()
            .find(|(k, _)| k == "per_page")
            .and_then(|(_, v)| v.parse().ok())
            .unwrap_or(20),
        search: query_pairs
            .iter()
            .find(|(k, _)| k == "search")
            .map(|(_, v)| v.clone()),
        tool: query_pairs
            .iter()
            .find(|(k, _)| k == "tool")
            .map(|(_, v)| v.clone()),
        team_id: query_pairs
            .iter()
            .find(|(k, _)| k == "team_id")
            .map(|(_, v)| v.clone()),
        sort: query_pairs
            .iter()
            .find(|(k, _)| k == "sort")
            .map(|(_, v)| v.clone()),
        time_range: query_pairs
            .iter()
            .find(|(k, _)| k == "time_range")
            .map(|(_, v)| v.clone()),
    };

    let built = service::build_session_list_query(&q);
    let d1 = storage::get_d1(&ctx.env)?;

    // Count total
    let count_params = to_d1_params(&built.count_params);
    let count_result = d1
        .prepare(&built.count_sql)
        .bind(&count_params)?
        .first::<storage::CountRow>(None)
        .await?;
    let total = count_result.map(|r| r.count).unwrap_or(0);

    // Fetch page
    let select_params = to_d1_params(&built.select_params);
    let rows_result = d1
        .prepare(&built.select_sql)
        .bind(&select_params)?
        .all()
        .await?;

    let sessions: Vec<SessionSummary> = rows_result
        .results::<storage::SessionRow>()?
        .into_iter()
        .map(SessionSummary::from)
        .collect();

    Response::from_json(&SessionListResponse {
        sessions,
        total,
        page: built.page,
        per_page: built.per_page,
    })
}

/// GET /api/sessions/:id — get session detail
pub async fn get(_req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let id = ctx.param("id").ok_or_else(|| Error::from("Missing id"))?;

    let d1 = storage::get_d1(&ctx.env)?;

    let row = d1
        .prepare(&*db::SESSION_GET)
        .bind(&[id.clone().into()])?
        .first::<storage::SessionRow>(None)
        .await?;

    match row {
        Some(s) => {
            let summary = SessionSummary::from(s);

            // Get team name
            let team_name = d1
                .prepare("SELECT name FROM teams WHERE id = ?1")
                .bind(&[summary.team_id.clone().into()])?
                .first::<serde_json::Value>(None)
                .await?
                .and_then(|v| {
                    v.get("name")
                        .and_then(|n| n.as_str())
                        .map(|n| n.to_string())
                });

            // Fetch linked sessions
            let linked_sessions: Vec<SessionLink> = d1
                .prepare(db::SESSION_LINKS_BY_SESSION)
                .bind(&[id.clone().into()])?
                .all()
                .await?
                .results::<SessionLink>()
                .unwrap_or_default();

            Response::from_json(&SessionDetail {
                summary,
                team_name,
                linked_sessions,
            })
        }
        None => ServiceError::NotFound("session not found".into()).into_err_response(),
    }
}

/// GET /api/sessions/:id/raw — get the full HAIL JSONL from R2 or redirect to body_url
pub async fn get_raw(_req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let id = ctx.param("id").ok_or_else(|| Error::from("Missing id"))?;

    let d1 = storage::get_d1(&ctx.env)?;

    // Get storage key and body_url from D1
    #[derive(serde::Deserialize)]
    struct StorageRow {
        body_storage_key: String,
        body_url: Option<String>,
    }

    let row = d1
        .prepare("SELECT body_storage_key, body_url FROM sessions WHERE id = ?1")
        .bind(&[id.clone().into()])?
        .first::<StorageRow>(None)
        .await?;

    let row = match row {
        Some(r) => r,
        None => {
            return ServiceError::NotFound("session not found".into()).into_err_response();
        }
    };

    // If body_url is set, redirect to external storage
    if let Some(ref url) = row.body_url {
        if !url.is_empty() {
            let headers = Headers::new();
            headers.set("Location", url)?;
            return Ok(Response::empty()?.with_status(302).with_headers(headers));
        }
    }

    // Fetch from R2
    match storage::get_session_body(&ctx.env, &row.body_storage_key).await? {
        Some(bytes) => {
            let headers = Headers::new();
            headers.set("Content-Type", "application/jsonl")?;
            headers.set(
                "Content-Disposition",
                "attachment; filename=\"session.hail.jsonl\"",
            )?;
            Ok(Response::from_bytes(bytes)?.with_headers(headers))
        }
        None => ServiceError::NotFound("session body not found".into()).into_err_response(),
    }
}

