/// Authenticated user extracted from `Authorization: Bearer <token>`.
///
/// Priority:
/// 1. `osk_` prefix → API key DB lookup (legacy)
/// 2. Otherwise → JWT verify → user_id DB lookup
pub struct AuthUser {
    pub user_id: String,
    pub nickname: String,
    pub is_admin: bool,
}

impl<S> FromRequestParts<S> for AuthUser
where
    S: Send + Sync,
    Db: FromRef<S>,
    AppConfig: FromRef<S>,
{
    type Rejection = ApiErr;

    async fn from_request_parts(parts: &mut Parts, state: &S) -> Result<Self, Self::Rejection> {
        let db = Db::from_ref(state);
        let config = AppConfig::from_ref(state);

        let token = parts
            .headers
            .get("authorization")
            .and_then(|v| v.to_str().ok())
            .and_then(|v| v.strip_prefix("Bearer "))
            .ok_or(ApiErr::unauthorized(
                "missing or invalid Authorization header",
            ))?
            .to_string();

        // API key path
        if token.starts_with("osk_") {
            let conn = db.conn();
            return conn
                .query_row(
                    "SELECT id, nickname, is_admin FROM users WHERE api_key = ?1",
                    [&token],
                    |row| {
                        Ok(AuthUser {
                            user_id: row.get(0)?,
                            nickname: row.get(1)?,
                            is_admin: row.get(2)?,
                        })
                    },
                )
                .map_err(|_| ApiErr::unauthorized("invalid API key"));
        }

        // JWT path
        if config.jwt_secret.is_empty() {
            return Err(ApiErr::unauthorized("JWT authentication not configured"));
        }

        let now = chrono::Utc::now().timestamp() as u64;
        let user_id = crypto::verify_jwt(&token, &config.jwt_secret, now)
            .map_err(|e| ApiErr::unauthorized(e.message()))?;

        let conn = db.conn();
        conn.query_row(
            "SELECT id, nickname, is_admin FROM users WHERE id = ?1",
            [&user_id],
            |row| {
                Ok(AuthUser {
                    user_id: row.get(0)?,
                    nickname: row.get(1)?,
                    is_admin: row.get(2)?,
                })
            },
        )
        .map_err(|_| ApiErr::unauthorized("user not found"))
    }
}

// ---------------------------------------------------------------------------
// Helpers
