fn validate_email(email: &str) -> Result<String, ServiceError> {
    let email = email.trim().to_lowercase();
    if email.is_empty() || !email.contains('@') || email.len() > 254 {
        return Err(ServiceError::BadRequest("invalid email address".into()));
    }
    Ok(email)
}

fn validate_password([REDACTED_CREDENTIAL] -> Result<(), ServiceError> {
    if password.len() < 8 {
        return Err(ServiceError::BadRequest(
            "password must be at least 8 characters".into(),
        ));
    }
    if password.len() > 12 {
        return Err(ServiceError::BadRequest(
            "password must be at most 12 characters".into(),
        ));
    }
    Ok(())
}

/// Public wrapper for oauth module to issue tokens.
pub fn issue_tokens_pub(
    db: &Db,
    jwt_[REDACTED_CREDENTIAL]
    user_id: &str,
    nickname: &str,
) -> Result<AuthTokenResponse, ApiErr> {
    issue_tokens(db, jwt_secret, user_id, nickname)
}

fn issue_tokens(
    db: &Db,
    jwt_[REDACTED_CREDENTIAL]
    user_id: &str,
    nickname: &str,
) -> Result<AuthTokenResponse, ApiErr> {
    let now = chrono::Utc::now().timestamp() as u64;
    let access_token = crypto::sign_jwt(user_id, jwt_secret, now);

    let refresh_token = crypto::generate_token();
    let token_hash = crypto::hash_token(&refresh_token);
    let token_id = Uuid::new_v4().to_string();
    let expires_at = (chrono::Utc::now()
        + chrono::Duration::seconds(crypto::REFRESH_EXPIRY_SECS as i64))
    .format("%Y-%m-%d %H:%M:%S")
    .to_string();

    let conn = db.conn();
    conn.execute(
        "INSERT INTO refresh_tokens (id, user_id, token_hash, expires_at) VALUES (?1, ?2, ?3, ?4)",
        rusqlite::params![token_id, user_id, token_hash, expires_at],
    )
    .map_err(ApiErr::from_db("issue_tokens"))?;

    Ok(AuthTokenResponse {
        access_token,
        refresh_token,
        expires_in: crypto::JWT_EXPIRY_SECS,
        user_id: user_id.to_string(),
        nickname: nickname.to_string(),
    })
}

fn is_first_user(db: &Db) -> bool {
    let conn = db.conn();
    let count: i64 = conn
        .query_row("SELECT COUNT(*) FROM users", [], |row| row.get(0))
        .unwrap_or(0);
    count == 0
}

// ---------------------------------------------------------------------------
// Register — first user becomes admin (legacy, CLI-compatible)
// ---------------------------------------------------------------------------

pub async fn register(
    State(db): State<Db>,
    Json(req): Json<RegisterRequest>,
) -> Result<(StatusCode, Json<RegisterResponse>), ApiErr> {
    let nickname = service::validate_nickname(&req.nickname).map_err(ApiErr::from)?;

    let user_id = Uuid::new_v4().to_string();
    let api_key = format!("osk_{}", Uuid::new_v4().simple());

    let conn = db.conn();

    let user_count: i64 = conn
        .query_row("SELECT COUNT(*) FROM users", [], |row| row.get(0))
        .unwrap_or(0);
    let is_admin = user_count == 0;

    let result = conn.execute(
        "INSERT INTO users (id, nickname, api_key, is_admin) VALUES (?1, ?2, ?3, ?4)",
        rusqlite::params![&user_id, &nickname, &api_key, is_admin],
    );

    match result {
        Ok(_) => Ok((
            StatusCode::CREATED,
            Json(RegisterResponse {
                user_id,
                nickname,
                api_key,
                is_admin,
            }),
        )),
        Err(rusqlite::Error::SqliteFailure(err, _))
            if err.code == rusqlite::ErrorCode::ConstraintViolation =>
        {
            Err(ApiErr::conflict("nickname already taken"))
        }
        Err(e) => {
            tracing::error!("register error: {e}");
            Err(ApiErr::internal("internal server error"))
        }
    }
}

