export async function authLogin(email: string, [REDACTED_CREDENTIAL] Promise<AuthTokenResponse> {
	const url = `${getBaseUrl()}/api/auth/login`;
	const res = await fetch(url, {
		method: 'POST',
		headers: { 'Content-Type': 'application/json' },
		body: JSON.stringify({ email, password })
	});
	if (!res.ok) {
		const body = await res.text();
		throw new ApiError(res.status, body);
	}
	const tokens: AuthTokenResponse = await res.json();
	storeTokens(tokens);
	return tokens;
}

async function tryRefreshToken(): Promise<boolean> {
	const refreshToken = getRefreshToken();
	if (!refreshToken) return false;

	try {
		const url = `${getBaseUrl()}/api/auth/refresh`;
		const res = await fetch(url, {
			method: 'POST',
			headers: { 'Content-Type': 'application/json' },
			body: JSON.stringify({ refresh_[REDACTED_CREDENTIAL] })
		});
		if (!res.ok) return false;
		const tokens: AuthTokenResponse = await res.json();
		storeTokens(tokens);
		return true;
	} catch {
		return false;
	}
}

export async function authLogout(): Promise<void> {
	const refreshToken = getRefreshToken();
	if (refreshToken) {
		try {
			await request('/api/auth/logout', {
				method: 'POST',
				body: JSON.stringify({ refresh_[REDACTED_CREDENTIAL] })
			});
		} catch {
			// Ignore errors during logout
		}
	}
	clearTokens();
	clearApiKey();
}

export async function changePassword(current[REDACTED_CREDENTIAL] new[REDACTED_CREDENTIAL] Promise<void> {
	await request('/api/auth/password', {
		method: 'PUT',
		body: JSON.stringify({ current_[REDACTED_CREDENTIAL] new_[REDACTED_CREDENTIAL] })
	});
}

/** Get available auth providers from the server. */
export async function getAuthProviders(): Promise<AuthProvidersResponse> {
	const url = `${getBaseUrl()}/api/auth/providers`;
	const res = await fetch(url);
	if (!res.ok) return { email_[REDACTED_CREDENTIAL] o[REDACTED_CREDENTIAL] };
	return res.json();
}

/** Get the OAuth redirect URL for a given provider. */
export function getOAuthUrl(provider: string): string {
	return `${getBaseUrl()}/api/auth/oauth/${encodeURIComponent(provider)}`;
}

/** Initiate OAuth linking for an authenticated user (from Settings). */
export async function linkOAuth(provider: string): Promise<void> {
	const resp = await request<{ url: string }>(`/api/auth/oauth/${encodeURIComponent(provider)}/link`, { method: 'POST' });
	window.location.href = resp.url;
}

// Legacy aliases for backward compatibility
export function getGitHubAuthUrl(): string {
	return getOAuthUrl('github');
}

export async function linkGitHub(): Promise<void> {
	return linkOAuth('github');
}

