#[cfg(all(test, feature = "ts"))]
mod tests {
    use super::*;
    use std::io::Write;
    use std::path::PathBuf;
    use ts_rs::TS;

    /// Run with: cargo test -p opensession-api-types -- export_typescript --nocapture
    #[test]
    fn export_typescript() {
        let out_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
            .join("../../packages/ui/src/api-types.generated.ts");

        let cfg = ts_rs::Config::new().with_large_int("number");
        let mut parts: Vec<String> = Vec::new();
        parts.push("// AUTO-GENERATED by opensession-api-types — DO NOT EDIT".to_string());
        parts.push(
            "// Regenerate with: cargo test -p opensession-api-types -- export_typescript"
                .to_string(),
        );
        parts.push(String::new());

        // Collect all type declarations, converting `type X = {...}` to `export interface X {...}`
        macro_rules! collect_ts {
            ($($t:ty),+ $(,)?) => {
                $(
                    let decl = <$t>::decl(&cfg);
                    // Convert `type Foo = { ... };` to `export interface Foo { ... }`
                    let decl = decl
                        .replacen("type ", "export interface ", 1)
                        .replace(" = {", " {")
                        .trim_end_matches(';')
                        .to_string();
                    parts.push(decl);
                    parts.push(String::new());
                )+
            };
        }

        collect_ts!(
            // Auth
            RegisterRequest,
            AuthRegisterRequest,
            LoginRequest,
            AuthTokenResponse,
            RefreshRequest,
            LogoutRequest,
            ChangePasswordRequest,
            RegisterResponse,
            VerifyResponse,
            UserSettingsResponse,
            // Sessions
            UploadResponse,
            SessionSummary,
            SessionListResponse,
            SessionListQuery,
            SessionDetail,
            // Teams
            CreateTeamRequest,
            TeamResponse,
            ListTeamsResponse,
            TeamDetailResponse,
            UpdateTeamRequest,
            TeamStatsQuery,
            TeamStatsResponse,
            TeamStatsTotals,
            UserStats,
            ToolStats,
            // Members
            AddMemberRequest,
            MemberResponse,
            ListMembersResponse,
            // Invitations
            InviteRequest,
            InvitationResponse,
            ListInvitationsResponse,
            AcceptInvitationResponse,
            // OAuth
            o[REDACTED_CREDENTIAL]
            o[REDACTED_CREDENTIAL]
            o[REDACTED_CREDENTIAL]
            // Health
            HealthResponse,
            ApiError,
        );

        let content = parts.join("\n");

        // Write to file
        if let Some(parent) = out_dir.parent() {
            std::fs::create_dir_all(parent).ok();
        }
        let mut file = std::fs::File::create(&out_dir)
            .unwrap_or_else(|e| panic!("Failed to create {}: {}", out_dir.display(), e));
        file.write_all(content.as_bytes())
            .unwrap_or_else(|e| panic!("Failed to write {}: {}", out_dir.display(), e));

        println!("Generated TypeScript types at: {}", out_dir.display());
    }
}

//! Generic OAuth2 provider support.
//!
//! Config-driven: no provider-specific code branches. Any OAuth2 provider
//! (GitHub, GitLab, Gitea, OIDC-compatible) can be added via configuration.
//!
//! This module contains only types, URL builders, and JSON parsing.
//! No HTTP calls or DB access — those live in the backend adapters.

use serde::{Deserialize, Serialize};

use crate::ServiceError;

// ── Provider Configuration ──────────────────────────────────────────────────

/// OAuth2 provider configuration. Loaded from environment variables or config file.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct OAuthProviderConfig {
    /// Unique provider identifier: "github", "gitlab-corp", "gitea-internal"
    pub id: String,
    /// UI display name: "GitHub", "GitLab (Corp)"
    pub display_name: String,

    // OAuth2 endpoints
    pub authorize_url: String,
    pub token_url: String,
    pub userinfo_url: String,
    /// Optional separate email endpoint (GitHub-specific: /user/emails)
    pub email_url: Option<String>,

    pub client_id: String,
    #[serde(skip_serializing)]
    pub client_[REDACTED_CREDENTIAL]
    pub scopes: String,

    /// JSON field mapping from userinfo response to internal fields
    pub field_map: OAuthFieldMap,

    /// Skip TLS verification for self-hosted instances (dev only)
    #[serde(default)]
    pub tls_skip_verify: bool,

    /// External URL for browser redirects (may differ from token_url for Docker setups)
    pub external_authorize_url: Option<String>,
}

/// Maps provider-specific JSON field names to our internal fields.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct OAuthFieldMap {
    /// Field containing the user's unique ID: "id" (GitHub/GitLab) or "sub" (OIDC)
    pub id: String,
    /// Field containing the username: "login" (GitHub) or "username" (GitLab)
    pub username: String,
    /// Field containing the email: "email"
    pub email: String,
    /// Field containing the avatar URL: "avatar_url" or "picture"
    pub avatar: String,
}

/// Normalized user info extracted from any OAuth provider's userinfo response.
#[derive(Debug, Clone)]
pub struct OAuthUserInfo {
    /// Provider config id (e.g. "github")
    pub provider_id: String,
    /// Provider-side user ID (as string)
    pub provider_user_id: String,
    pub username: String,
    pub email: Option<String>,
    pub avatar_url: Option<String>,
}

// ── URL Builders (pure functions, no HTTP) ──────────────────────────────────

/// Build the OAuth authorize URL that the user's browser should be redirected to.
pub fn build_authorize_url(
    config: &OAuthProviderConfig,
    redirect_uri: &str,
    state: &str,
) -> String {
    let base = config
        .external_authorize_url
        .as_deref()
        .unwrap_or(&config.authorize_url);

    format!(
        "{}?client_id={}&redirect_uri={}&state={}&scope={}&response_type=code",
        base,
        urlencoding(&config.client_id),
        urlencoding(redirect_uri),
        urlencoding(state),
        urlencoding(&config.scopes),
    )
}

/// Build the JSON body for the token exchange request.
pub fn build_token_request_body(
    config: &OAuthProviderConfig,
    code: &str,
    redirect_uri: &str,
) -> serde_json::Value {
    serde_json::json!({
        "client_id": config.client_id,
        "client_secret": config.client_secret,
        "code": code,
        "grant_type": "authorization_code",
        "redirect_uri": redirect_uri,
    })
}

/// Extract normalized user info from a provider's userinfo JSON response.
///
/// `email_json` is an optional array of email objects (GitHub `/user/emails` format)
/// used when the primary userinfo endpoint doesn't include the email.
pub fn extract_user_info(
    config: &OAuthProviderConfig,
    userinfo_json: &serde_json::Value,
    email_json: Option<&[serde_json::Value]>,
) -> Result<OAuthUserInfo, ServiceError> {
    // Extract provider user ID — may be number or string depending on provider
    let provider_user_id = match &userinfo_json[&config.field_map.id] {
        serde_json::Value::Number(n) => n.to_string(),
        serde_json::Value::String(s) => s.clone(),
        _ => {
            return Err(ServiceError::Internal(format!(
                "OAuth userinfo missing '{}' field",
                config.field_map.id
            )))
        }
    };

    let username = userinfo_json[&config.field_map.username]
        .as_str()
        .unwrap_or("unknown")
        .to_string();

    // Email: try userinfo first, then email_json (GitHub format: [{email, primary, verified}])
    let email = userinfo_json[&config.field_map.email]
        .as_str()
        .map(|s| s.to_string())
        .or_else(|| {
            email_json.and_then(|emails| {
                emails
                    .iter()
                    .find(|e| e["primary"].as_bool() == Some(true))
                    .and_then(|e| e["email"].as_str())
                    .map(|s| s.to_string())
            })
        });

    let avatar_url = userinfo_json[&config.field_map.avatar]
        .as_str()
        .map(|s| s.to_string());

    Ok(OAuthUserInfo {
        provider_id: config.id.clone(),
        provider_user_id,
        username,
        email,
        avatar_url,
    })
}

// ── Provider Presets ────────────────────────────────────────────────────────

/// Create a GitHub OAuth2 provider config. Only needs client credentials.
pub fn github_preset(client_id: String, client_[REDACTED_CREDENTIAL] -> OAuthProviderConfig {
    OAuthProviderConfig {
        id: "github".into(),
        display_name: "GitHub".into(),
        authorize_url: "https://github.com/login/oauth/authorize".into(),
        token_url: "https://github.com/login/oauth/access_token".into(),
        userinfo_url: "https://api.github.com/user".into(),
        email_url: Some("https://api.github.com/user/emails".into()),
        client_id,
        client_secret,
        scopes: "read:user,user:email".into(),
        field_map: OAuthFieldMap {
            id: "id".into(),
            username: "login".into(),
            email: "email".into(),
            avatar: "avatar_url".into(),
        },
        tls_skip_verify: false,
        external_authorize_url: None,
    }
}

/// Create a GitLab OAuth2 provider config for a given instance URL.
///
/// `instance_url` is the server-accessible URL (e.g. `http://gitlab:80` in Docker).
/// `external_url` is the browser-accessible URL (e.g. `http://localhost:8929`).
/// If `external_url` is None, `instance_url` is used for browser redirects too.
pub fn gitlab_preset(
    instance_url: String,
    external_url: Option<String>,
    client_id: String,
    client_[REDACTED_CREDENTIAL]
) -> OAuthProviderConfig {
    let base = instance_url.trim_end_matches('/');
    let ext_base = external_url
        .as_deref()
        .map(|u| u.trim_end_matches('/').to_string());

    OAuthProviderConfig {
        id: "gitlab".into(),
        display_name: "GitLab".into(),
        authorize_url: format!("{base}/oauth/authorize"),
        token_url: format!("{base}/oauth/token"),
        userinfo_url: format!("{base}/api/v4/user"),
        email_url: None, // GitLab includes email in /api/v4/user
        client_id,
        client_secret,
        scopes: "read_user".into(),
        field_map: OAuthFieldMap {
            id: "id".into(),
            username: "username".into(),
            email: "email".into(),
            avatar: "avatar_url".into(),
        },
        tls_skip_verify: false,
        external_authorize_url: ext_base.map(|b| format!("{b}/oauth/authorize")),
    }
}

// ── API Response Types ──────────────────────────────────────────────────────

/// Available auth providers (returned by GET /api/auth/providers).
#[derive(Debug, Serialize, Deserialize)]
#[cfg_attr(feature = "ts", derive(ts_rs::TS))]
#[cfg_attr(feature = "ts", ts(export))]
pub struct AuthProvidersResponse {
    pub email_[REDACTED_CREDENTIAL]
    pub o[REDACTED_CREDENTIAL]
}

/// Public info about an OAuth provider.
#[derive(Debug, Serialize, Deserialize)]
#[cfg_attr(feature = "ts", derive(ts_rs::TS))]
#[cfg_attr(feature = "ts", ts(export))]
pub struct OAuthProviderInfo {
    pub id: String,
    pub display_name: String,
}

/// A linked OAuth provider shown in user settings.
#[derive(Debug, Serialize, Deserialize)]
#[cfg_attr(feature = "ts", derive(ts_rs::TS))]
#[cfg_attr(feature = "ts", ts(export))]
pub struct LinkedProvider {
    pub provider: String,
    pub provider_username: String,
    pub display_name: String,
}

// ── Helpers ─────────────────────────────────────────────────────────────────

fn urlencoding(s: &str) -> String {
    // Minimal URL-encoding for OAuth parameters
    let mut out = String::with_capacity(s.len());
    for b in s.bytes() {
        match b {
            b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'_' | b'.' | b'~' => {
                out.push(b as char);
            }
            _ => {
                out.push('%');
                out.push(char::from(b"0123456789ABCDEF"[(b >> 4) as usize]));
                out.push(char::from(b"0123456789ABCDEF"[(b & 0x0f) as usize]));
            }
        }
    }
    out
}

//! Shared business logic — framework-agnostic pure functions.
//!
//! Both the Axum server and Cloudflare Worker call these functions,
//! keeping route handlers as thin adapters.

use crate::{db, ServiceError, SessionListQuery};

// ─── Validation ─────────────────────────────────────────────────────────────

/// Validate and normalize a user nickname. Returns the trimmed nickname.
pub fn validate_nickname(nickname: &str) -> Result<String, ServiceError> {
    let trimmed = nickname.trim().to_string();
    if trimmed.is_empty() || trimmed.len() > 64 {
        return Err(ServiceError::BadRequest(
            "nickname must be 1-64 characters".into(),
        ));
    }
    Ok(trimmed)
}

/// Validate and normalize a team name. Returns the trimmed name.
pub fn validate_team_name(name: &str) -> Result<String, ServiceError> {
    let trimmed = name.trim().to_string();
    if trimmed.is_empty() || trimmed.len() > 128 {
        return Err(ServiceError::BadRequest(
            "name must be 1-128 characters".into(),
        ));
    }
    Ok(trimmed)
}

// ─── Session List Query Builder ─────────────────────────────────────────────

/// Abstract query parameter value, framework-agnostic.
///
/// Each backend converts this into its native bind type:
/// - Axum/rusqlite: `Box<dyn ToSql>`
/// - Worker/D1: `JsValue`
#[derive(Debug, Clone)]
pub enum ParamValue {
    Text(String),
    Int(i64),
}

/// Result of building a session list query from [`SessionListQuery`].
pub struct BuiltSessionListQuery {
    /// SQL for counting total results: `SELECT COUNT(*) as count FROM sessions s WHERE {where_clause}`
    pub count_sql: String,
    /// SQL for fetching a page: `SELECT ... FROM sessions s LEFT JOIN users u ... WHERE ... ORDER BY ... LIMIT ?N OFFSET ?N+1`
    pub select_sql: String,
    /// Bind params for the count query.
    pub count_params: Vec<ParamValue>,
    /// Bind params for the select query (count_params + LIMIT + OFFSET).
    pub select_params: Vec<ParamValue>,
    /// Current page number (from the query).
    pub page: u32,
    /// Clamped per_page value.
    pub per_page: u32,
}

/// Build framework-agnostic SQL + params for paginated session listing.
///
/// The generated SQL uses the shared `SESSION_COLUMNS` and numbered `?N` bind
/// parameters compatible with both SQLite and D1.
pub fn build_session_list_query(q: &SessionListQuery) -> BuiltSessionListQuery {
    let per_page = q.per_page.clamp(1, 100);
    let offset = (q.page.saturating_sub(1)) * per_page;

    let mut where_parts = vec!["(s.event_count > 0 OR s.message_count > 0)".to_string()];
    let mut params: Vec<ParamValue> = Vec::new();
    let mut idx = 1u32;

    if let Some(ref tool) = q.tool {
        where_parts.push(format!("s.tool = ?{idx}"));
        params.push(ParamValue::Text(tool.clone()));
        idx += 1;
    }

    if let Some(ref team_id) = q.team_id {
        where_parts.push(format!("s.team_id = ?{idx}"));
        params.push(ParamValue::Text(team_id.clone()));
        idx += 1;
    }

    if let Some(ref search) = q.search {
        let like = format!("%{search}%");
        where_parts.push(format!(
            "(s.title LIKE ?{p1} OR s.description LIKE ?{p2} OR s.tags LIKE ?{p3})",
            p1 = idx,
            p2 = idx + 1,
            p3 = idx + 2,
        ));
        params.push(ParamValue::Text(like.clone()));
        params.push(ParamValue::Text(like.clone()));
        params.push(ParamValue::Text(like));
        idx += 3;
    }

    if let Some(ref time_range) = q.time_range {
        let interval = match time_range.as_str() {
            "24h" => Some("-1 day"),
            "7d" => Some("-7 days"),
            "30d" => Some("-30 days"),
            _ => None,
        };
        if let Some(interval) = interval {
            where_parts.push(format!("s.created_at >= datetime('now', ?{idx})"));
            params.push(ParamValue::Text(interval.to_string()));
            idx += 1;
        }
    }

    let where_clause = where_parts.join(" AND ");

    let order_clause = match q.sort.as_deref() {
        Some("popular") => "s.message_count DESC, s.created_at DESC",
        Some("longest") => "s.duration_seconds DESC, s.created_at DESC",
        _ => "s.created_at DESC",
    };

    let count_sql = format!("SELECT COUNT(*) as count FROM sessions s WHERE {where_clause}");

    let select_sql = format!(
        "SELECT {} \
         FROM sessions s \
         LEFT JOIN users u ON u.id = s.user_id \
         WHERE {where_clause} \
         ORDER BY {order_clause} \
         LIMIT ?{idx} OFFSET ?{}",
        db::SESSION_COLUMNS,
        idx + 1,
    );

    let mut select_params = params.clone();
    select_params.push(ParamValue::Int(per_page as i64));
    select_params.push(ParamValue::Int(offset as i64));

    BuiltSessionListQuery {
        count_sql,
        select_sql,
        count_params: params,
        select_params,
        page: q.page,
        per_page,
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_validate_nickname() {
        assert!(validate_nickname("alice").is_ok());
        assert_eq!(validate_nickname("  bob  ").unwrap(), "bob");
        assert!(validate_nickname("").is_err());
        assert!(validate_nickname("   ").is_err());
        assert!(validate_nickname(&"x".repeat(65)).is_err());
        assert!(validate_nickname(&"x".repeat(64)).is_ok());
    }

    #[test]
    fn test_validate_team_name() {
        assert!(validate_team_name("my-team").is_ok());
        assert_eq!(validate_team_name("  team  ").unwrap(), "team");
        assert!(validate_team_name("").is_err());
        assert!(validate_team_name("   ").is_err());
        assert!(validate_team_name(&"x".repeat(129)).is_err());
        assert!(validate_team_name(&"x".repeat(128)).is_ok());
    }

    #[test]
    fn test_build_session_list_query_defaults() {
        let q = SessionListQuery {
            page: 1,
            per_page: 20,
            search: None,
            tool: None,
            team_id: None,
            sort: None,
            time_range: None,
        };
        let built = build_session_list_query(&q);
        assert!(built
            .count_sql
            .contains("WHERE (s.event_count > 0 OR s.message_count > 0)"));
        assert!(built.select_sql.contains("ORDER BY s.created_at DESC"));
        assert!(built.count_params.is_empty());
        assert_eq!(built.select_params.len(), 2); // LIMIT + OFFSET
        assert_eq!(built.page, 1);
        assert_eq!(built.per_page, 20);
    }

    #[test]
    fn test_build_session_list_query_with_filters() {
        let q = SessionListQuery {
            page: 2,
            per_page: 10,
            search: Some("rust".into()),
            tool: Some("claude-code".into()),
            team_id: Some("team-1".into()),
            sort: Some("popular".into()),
            time_range: Some("7d".into()),
        };
        let built = build_session_list_query(&q);
        assert!(built.count_sql.contains("s.tool = ?1"));
        assert!(built.count_sql.contains("s.team_id = ?2"));
        assert!(built.count_sql.contains("s.title LIKE ?3"));
        assert!(built.count_sql.contains("datetime('now', ?6)"));
        assert!(built.select_sql.contains("ORDER BY s.message_count DESC"));
        // 1 tool + 1 team_id + 3 search + 1 time_range = 6 count params
        assert_eq!(built.count_params.len(), 6);
        // + 2 for LIMIT/OFFSET
        assert_eq!(built.select_params.len(), 8);
        assert_eq!(built.per_page, 10);
    }

    #[test]
    fn test_build_session_list_query_clamps_per_page() {
        let q = SessionListQuery {
            page: 1,
            per_page: 500,
            search: None,
            tool: None,
            team_id: None,
            sort: None,
            time_range: None,
        };
        let built = build_session_list_query(&q);
        assert_eq!(built.per_page, 100);
    }
}

