pub const MEMBER_DELETE: &str = "\
DELETE FROM team_members WHERE team_id = ?1 AND user_id = ?2";

/// List members of a team (joins with users table).
pub static MEMBER_LIST: LazyLock<String> = LazyLock::new(|| {
    format!(
        "SELECT {MEMBER_COLUMNS} \
         FROM team_members tm \
         INNER JOIN users u ON u.id = tm.user_id \
         WHERE tm.team_id = ?1 \
         ORDER BY tm.joined_at ASC"
    )
});

// ─── Session links ──────────────────────────────────────────────────────────

/// INSERT a session link.
pub const SESSION_LINK_INSERT: &str = "\
INSERT OR IGNORE INTO session_links (session_id, linked_session_id, link_type) \
VALUES (?1, ?2, ?3)";

/// SELECT all links for a session (both directions).
pub const SESSION_LINKS_BY_SESSION: &str = "\
SELECT session_id, linked_session_id, link_type, created_at \
FROM session_links \
WHERE session_id = ?1 OR linked_session_id = ?1";

// ─── OAuth Identities ────────────────────────────────────────────────────────

/// Schema for the generic OAuth identities table (used by migration).
pub const OAUTH_IDENTITIES_SCHEMA: &str = "\
CREATE TABLE IF NOT EXISTS oauth_identities (
    user_id           TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    provider          TEXT NOT NULL,
    provider_user_id  TEXT NOT NULL,
    provider_username TEXT,
    avatar_url        TEXT,
    instance_url      TEXT,
    created_at        TEXT NOT NULL DEFAULT (datetime('now')),
    PRIMARY KEY (provider, provider_user_id),
    UNIQUE (user_id, provider)
);
";

/// Schema for OAuth state tokens (CSRF protection).
pub const OAUTH_STATES_SCHEMA: &str = "\
CREATE TABLE IF NOT EXISTS oauth_states (
    state      TEXT PRIMARY KEY,
    provider   TEXT NOT NULL,
    created_at TEXT NOT NULL DEFAULT (datetime('now')),
    expires_at TEXT NOT NULL,
    user_id    TEXT
);
";

/// Schema for refresh tokens.
pub const REFRESH_TOKENS_SCHEMA: &str = "\
CREATE TABLE IF NOT EXISTS refresh_tokens (
    id         TEXT PRIMARY KEY,
    user_id    TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    token_hash TEXT NOT NULL UNIQUE,
    expires_at TEXT NOT NULL,
    created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
";

/// UPSERT an OAuth identity (link or update).
pub const OAUTH_IDENTITY_UPSERT: &str = "\
INSERT INTO oauth_identities (user_id, provider, provider_user_id, provider_username, avatar_url, instance_url) \
VALUES (?1, ?2, ?3, ?4, ?5, ?6) \
ON CONFLICT (provider, provider_user_id) DO UPDATE SET \
    provider_username = excluded.provider_username, \
    avatar_url = excluded.avatar_url";

/// Find a user by OAuth identity.
pub const OAUTH_IDENTITY_FIND_BY_PROVIDER: &str = "\
SELECT user_id, provider, provider_user_id, provider_username, avatar_url, instance_url \
FROM oauth_identities WHERE provider = ?1 AND provider_user_id = ?2";

/// Find all OAuth identities for a user.
pub const OAUTH_IDENTITY_FIND_BY_USER: &str = "\
SELECT user_id, provider, provider_user_id, provider_username, avatar_url, instance_url \
FROM oauth_identities WHERE user_id = ?1";

/// Insert an OAuth state token.
pub const OAUTH_STATE_INSERT: &str = "\
INSERT INTO oauth_states (state, provider, expires_at, user_id) VALUES (?1, ?2, ?3, ?4)";

/// Validate and retrieve an OAuth state token.
pub const OAUTH_STATE_VALIDATE: &str = "\
SELECT state, provider, expires_at, user_id FROM oauth_states WHERE state = ?1";

/// Delete a used OAuth state token.
pub const OAUTH_STATE_DELETE: &str = "\
DELETE FROM oauth_states WHERE state = ?1";

// ─── Invitations ─────────────────────────────────────────────────────────────

/// Column list for invitation SELECT queries.
pub const INVITATION_COLUMNS: &str = "\
i.id, i.team_id, t.name AS team_name, i.email, i.github_username, \
u.nickname AS invited_by_nickname, i.role, i.status, i.created_at, i.expires_at";

/// INSERT a new invitation.
pub const INVITATION_INSERT: &str = "\
INSERT INTO team_invitations (id, team_id, email, github_username, invited_by, role, expires_at) \
VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7)";

/// List pending invitations for a user by email or github_username.
/// ?1 = email, ?2 = github_username
pub static INVITATION_LIST_MY: LazyLock<String> = LazyLock::new(|| {
    format!(
        "SELECT {INVITATION_COLUMNS} \
         FROM team_invitations i \
         INNER JOIN teams t ON t.id = i.team_id \
         INNER JOIN users u ON u.id = i.invited_by \
         WHERE i.status = 'pending' \
         AND i.expires_at > datetime('now') \
         AND ((i.email IS NOT NULL AND i.email = ?1) \
              OR (i.github_username IS NOT NULL AND i.github_username = ?2)) \
         ORDER BY i.created_at DESC"
    )
});

