        let cfg = ts_rs::Config::new().with_large_int("number");
        let mut parts: Vec<String> = Vec::new();
        parts.push("// AUTO-GENERATED by opensession-api-types — DO NOT EDIT".to_string());
        parts.push(
            "// Regenerate with: cargo test -p opensession-api-types -- export_typescript"
                .to_string(),
        );
        parts.push(String::new());

        // Collect all type declarations, converting `type X = {...}` to `export interface X {...}`
        macro_rules! collect_ts {
            ($($t:ty),+ $(,)?) => {
                $(
                    let decl = <$t>::decl(&cfg);
                    // Convert `type Foo = { ... };` to `export interface Foo { ... }`
                    let decl = decl
                        .replacen("type ", "export interface ", 1)
                        .replace(" = {", " {")
                        .trim_end_matches(';')
                        .to_string();
                    parts.push(decl);
                    parts.push(String::new());
                )+
            };
        }

        collect_ts!(
            // Auth
            RegisterRequest,
            AuthRegisterRequest,
            LoginRequest,
            AuthTokenResponse,
            RefreshRequest,
            LogoutRequest,
            ChangePasswordRequest,
            RegisterResponse,
            VerifyResponse,
            UserSettingsResponse,
            // Sessions
            UploadResponse,
            SessionSummary,
            SessionListResponse,
            SessionListQuery,
            SessionDetail,
            // Teams
            CreateTeamRequest,
            TeamResponse,
            ListTeamsResponse,
            TeamDetailResponse,
            UpdateTeamRequest,
            TeamStatsQuery,
            TeamStatsResponse,
            TeamStatsTotals,
            UserStats,
            ToolStats,
            // Members
            AddMemberRequest,
            MemberResponse,
            ListMembersResponse,
            // Invitations
            InviteRequest,
            InvitationResponse,
            ListInvitationsResponse,
            AcceptInvitationResponse,
            // OAuth
            o[REDACTED_CREDENTIAL]
            o[REDACTED_CREDENTIAL]
            o[REDACTED_CREDENTIAL]
            // Health
            HealthResponse,
            ApiError,
        );

        let content = parts.join("\n");

        // Write to file
        if let Some(parent) = out_dir.parent() {
            std::fs::create_dir_all(parent).ok();
        }
        let mut file = std::fs::File::create(&out_dir)
            .unwrap_or_else(|e| panic!("Failed to create {}: {}", out_dir.display(), e));
        file.write_all(content.as_bytes())
            .unwrap_or_else(|e| panic!("Failed to write {}: {}", out_dir.display(), e));

        println!("Generated TypeScript types at: {}", out_dir.display());
    }
}

