// Auth extractor — JWT + API key dual auth
// ---------------------------------------------------------------------------

/// Authenticated user extracted from `Authorization: Bearer <token>`.
///
/// Priority:
/// 1. `osk_` prefix → API key DB lookup (legacy)
/// 2. Otherwise → JWT verify → user_id DB lookup
pub struct AuthUser {
    pub user_id: String,
    pub nickname: String,
    pub is_admin: bool,
}

impl<S> FromRequestParts<S> for AuthUser
where
    S: Send + Sync,
    Db: FromRef<S>,
    AppConfig: FromRef<S>,
{
    type Rejection = ApiErr;

    async fn from_request_parts(parts: &mut Parts, state: &S) -> Result<Self, Self::Rejection> {
        let db = Db::from_ref(state);
        let config = AppConfig::from_ref(state);

        let token = parts
            .headers
            .get("authorization")
            .and_then(|v| v.to_str().ok())
            .and_then(|v| v.strip_prefix("Bearer "))
            .ok_or(ApiErr::unauthorized(
                "missing or invalid Authorization header",
            ))?
            .to_string();

        // API key path
        if token.starts_with("osk_") {
            let conn = db.conn();
            return conn
                .query_row(
                    "SELECT id, nickname, is_admin FROM users WHERE api_key = ?1",
                    [&token],
                    |row| {
                        Ok(AuthUser {
                            user_id: row.get(0)?,
                            nickname: row.get(1)?,
                            is_admin: row.get(2)?,
                        })
                    },
                )
                .map_err(|_| ApiErr::unauthorized("invalid API key"));
        }

        // JWT path
        if config.jwt_secret.is_empty() {
            return Err(ApiErr::unauthorized("JWT authentication not configured"));
        }

        let now = chrono::Utc::now().timestamp() as u64;
        let user_id = crypto::verify_jwt(&token, &config.jwt_secret, now)
            .map_err(|e| ApiErr::unauthorized(e.message()))?;

        let conn = db.conn();
        conn.query_row(
            "SELECT id, nickname, is_admin FROM users WHERE id = ?1",
            [&user_id],
            |row| {
                Ok(AuthUser {
                    user_id: row.get(0)?,
                    nickname: row.get(1)?,
                    is_admin: row.get(2)?,
                })
            },
        )
        .map_err(|_| ApiErr::unauthorized("user not found"))
    }
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

fn validate_email(email: &str) -> Result<String, ServiceError> {
    let email = email.trim().to_lowercase();
    if email.is_empty() || !email.contains('@') || email.len() > 254 {
        return Err(ServiceError::BadRequest("invalid email address".into()));
    }
    Ok(email)
}

fn validate_password([REDACTED_CREDENTIAL] -> Result<(), ServiceError> {
    if password.len() < 8 {
        return Err(ServiceError::BadRequest(
            "password must be at least 8 characters".into(),
        ));
    }
    if password.len() > 12 {
        return Err(ServiceError::BadRequest(
            "password must be at most 12 characters".into(),
        ));
    }
    Ok(())
}

/// Public wrapper for oauth module to issue tokens.
pub fn issue_tokens_pub(
    db: &Db,
    jwt_[REDACTED_CREDENTIAL]
    user_id: &str,
    nickname: &str,
) -> Result<AuthTokenResponse, ApiErr> {
    issue_tokens(db, jwt_secret, user_id, nickname)
}

fn issue_tokens(
    db: &Db,
    jwt_[REDACTED_CREDENTIAL]
    user_id: &str,
    nickname: &str,
) -> Result<AuthTokenResponse, ApiErr> {
    let now = chrono::Utc::now().timestamp() as u64;
    let access_token = crypto::sign_jwt(user_id, jwt_secret, now);

    let refresh_token = crypto::generate_token();
    let token_hash = crypto::hash_token(&refresh_token);
    let token_id = Uuid::new_v4().to_string();
    let expires_at = (chrono::Utc::now()
        + chrono::Duration::seconds(crypto::REFRESH_EXPIRY_SECS as i64))
    .format("%Y-%m-%d %H:%M:%S")
    .to_string();

    let conn = db.conn();
    conn.execute(
        "INSERT INTO refresh_tokens (id, user_id, token_hash, expires_at) VALUES (?1, ?2, ?3, ?4)",
        rusqlite::params![token_id, user_id, token_hash, expires_at],
    )
    .map_err(ApiErr::from_db("issue_tokens"))?;

    Ok(AuthTokenResponse {
        access_token,
        refresh_token,
        expires_in: crypto::JWT_EXPIRY_SECS,
        user_id: user_id.to_string(),
        nickname: nickname.to_string(),
    })
}

fn is_first_user(db: &Db) -> bool {
    let conn = db.conn();
    let count: i64 = conn
        .query_row("SELECT COUNT(*) FROM users", [], |row| row.get(0))
        .unwrap_or(0);
    count == 0
}

// ---------------------------------------------------------------------------
// Register — first user becomes admin (legacy, CLI-compatible)
// ---------------------------------------------------------------------------

pub async fn register(
    State(db): State<Db>,
    Json(req): Json<RegisterRequest>,
) -> Result<(StatusCode, Json<RegisterResponse>), ApiErr> {
    let nickname = service::validate_nickname(&req.nickname).map_err(ApiErr::from)?;

    let user_id = Uuid::new_v4().to_string();
    let api_key = format!("osk_{}", Uuid::new_v4().simple());

    let conn = db.conn();

    let user_count: i64 = conn
        .query_row("SELECT COUNT(*) FROM users", [], |row| row.get(0))
        .unwrap_or(0);
    let is_admin = user_count == 0;

    let result = conn.execute(
        "INSERT INTO users (id, nickname, api_key, is_admin) VALUES (?1, ?2, ?3, ?4)",
        rusqlite::params![&user_id, &nickname, &api_key, is_admin],
    );

    match result {
        Ok(_) => Ok((
            StatusCode::CREATED,
            Json(RegisterResponse {
                user_id,
                nickname,
                api_key,
                is_admin,
            }),
        )),
        Err(rusqlite::Error::SqliteFailure(err, _))
            if err.code == rusqlite::ErrorCode::ConstraintViolation =>
        {
            Err(ApiErr::conflict("nickname already taken"))
        }
        Err(e) => {
            tracing::error!("register error: {e}");
            Err(ApiErr::internal("internal server error"))
        }
    }
}

// ---------------------------------------------------------------------------
// Email/password auth
// ---------------------------------------------------------------------------

/// POST /api/auth/register — email + password registration
pub async fn auth_register(
    State(db): State<Db>,
    State(config): State<AppConfig>,
    Json(req): Json<AuthRegisterRequest>,
) -> Result<(StatusCode, Json<AuthTokenResponse>), ApiErr> {
    if config.jwt_secret.is_empty() {
        return Err(ApiErr::internal("JWT_SECRET not configured"));
    }

    let email = validate_email(&req.email).map_err(ApiErr::from)?;
    validate_password(&req.password).map_err(ApiErr::from)?;
    let nickname = service::validate_nickname(&req.nickname).map_err(ApiErr::from)?;

    // Check email uniqueness
    {
        let conn = db.conn();
        let exists: bool = conn
            .query_row(
                "SELECT COUNT(*) > 0 FROM users WHERE email = ?1",
                [&email],
                |row| row.get(0),
            )
            .unwrap_or(false);
        if exists {
            return Err(ApiErr::conflict("email already registered"));
        }
    }

    let user_id = Uuid::new_v4().to_string();
    let api_key = format!("osk_{}", Uuid::new_v4().simple());
    let (password_hash, password_salt) = crypto::hash_password(&req.password);
    let admin = is_first_user(&db);

    {
        let conn = db.conn();
        let result = conn.execute(
            "INSERT INTO users (id, nickname, api_key, is_admin, email, password_hash, password_salt) \
             VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7)",
            rusqlite::params![user_id, nickname, api_key, admin, email, password_hash, password_salt],
        );
        match result {
            Ok(_) => {}
            Err(rusqlite::Error::SqliteFailure(err, _))
                if err.code == rusqlite::ErrorCode::ConstraintViolation =>
            {
                return Err(ApiErr::conflict("nickname already taken"));
            }
            Err(e) => {
                tracing::error!("auth_register error: {e}");
                return Err(ApiErr::internal("internal server error"));
            }
        }
    }

    let tokens = issue_tokens(&db, &config.jwt_secret, &user_id, &nickname)?;
    Ok((StatusCode::CREATED, Json(tokens)))
}

/// POST /api/auth/login — email + password login
pub async fn login(
    State(db): State<Db>,
    State(config): State<AppConfig>,
    Json(req): Json<LoginRequest>,
) -> Result<Json<AuthTokenResponse>, ApiErr> {
    if config.jwt_secret.is_empty() {
        return Err(ApiErr::internal("JWT_SECRET not configured"));
    }

    let email = validate_email(&req.email).map_err(ApiErr::from)?;

    let conn = db.conn();
    let user = conn
        .query_row(
            "SELECT id, nickname, password_hash, password_salt FROM users WHERE email = ?1",
            [&email],
            |row| {
                Ok((
                    row.get::<_, String>(0)?,
                    row.get::<_, String>(1)?,
                    row.get::<_, Option<String>>(2)?,
                    row.get::<_, Option<String>>(3)?,
                ))
            },
        )
        .map_err(|_| ApiErr::unauthorized("invalid email or password"))?;

    let (user_id, nickname, hash, salt) = user;
    let (hash, salt) = match (hash, salt) {
        (Some(h), Some(s)) => (h, s),
        _ => {
            return Err(ApiErr::unauthorized(
                "this account uses OAuth login, not email/password",
            ))
        }
    };

    if !crypto::verify_password(&req.password, &hash, &salt) {
        return Err(ApiErr::unauthorized("invalid email or password"));
    }
    drop(conn);

    let tokens = issue_tokens(&db, &config.jwt_secret, &user_id, &nickname)?;
    Ok(Json(tokens))
}

/// POST /api/auth/refresh — exchange refresh token for new JWT
pub async fn refresh(
    State(db): State<Db>,
    State(config): State<AppConfig>,
    Json(req): Json<RefreshRequest>,
) -> Result<Json<AuthTokenResponse>, ApiErr> {
    if config.jwt_secret.is_empty() {
        return Err(ApiErr::internal("JWT_SECRET not configured"));
    }

    let token_hash = crypto::hash_token(&req.refresh_token);

    let conn = db.conn();
    let row = conn
        .query_row(
            "SELECT rt.id, rt.user_id, rt.expires_at, u.nickname \
             FROM refresh_tokens rt \
             JOIN users u ON u.id = rt.user_id \
             WHERE rt.token_hash = ?1",
            [&token_hash],
            |row| {
                Ok((
                    row.get::<_, String>(0)?,
                    row.get::<_, String>(1)?,
                    row.get::<_, String>(2)?,
                    row.get::<_, String>(3)?,
                ))
            },
        )
        .map_err(|_| ApiErr::unauthorized("invalid refresh token"))?;

    let (rt_id, user_id, expires_at, nickname) = row;

    let now = chrono::Utc::now().format("%Y-%m-%d %H:%M:%S").to_string();
    if expires_at < now {
        conn.execute("DELETE FROM refresh_tokens WHERE id = ?1", [&rt_id])
            .ok();
        return Err(ApiErr::unauthorized("refresh token expired"));
    }

    // Rotate: delete old, issue new
    conn.execute(
        "DELETE FROM refresh_tokens WHERE token_hash = ?1",
        [&token_hash],
    )
    .ok();
    drop(conn);

    let tokens = issue_tokens(&db, &config.jwt_secret, &user_id, &nickname)?;
    Ok(Json(tokens))
}

/// POST /api/auth/logout — invalidate refresh token
pub async fn logout(
    State(db): State<Db>,
    Json(req): Json<LogoutRequest>,
) -> Result<Json<serde_json::Value>, ApiErr> {
    let token_hash = crypto::hash_token(&req.refresh_token);
    let conn = db.conn();
    conn.execute(
        "DELETE FROM refresh_tokens WHERE token_hash = ?1",
        [&token_hash],
    )
    .ok();
    Ok(Json(serde_json::json!({"ok": true})))
}

/// PUT /api/auth/password — change password (authenticated)
pub async fn change_password(
    State(db): State<Db>,
    user: AuthUser,
    Json(req): Json<ChangePasswordRequest>,
) -> Result<Json<serde_json::Value>, ApiErr> {
    let conn = db.conn();
    let (hash, salt): (Option<String>, Option<String>) = conn
        .query_row(
            "SELECT password_hash, password_salt FROM users WHERE id = ?1",
            [&user.user_id],
            |row| Ok((row.get(0)?, row.get(1)?)),
        )
        .map_err(ApiErr::from_db("change_password lookup"))?;

    let (hash, salt) = match (hash, salt) {
        (Some(h), Some(s)) => (h, s),
        _ => {
            return Err(ApiErr::bad_request(
                "cannot change password for OAuth-only account",
            ))
        }
    };

    if !crypto::verify_password(&req.current_password, &hash, &salt) {
        return Err(ApiErr::unauthorized("current password is incorrect"));
    }

    validate_password(&req.new_password).map_err(ApiErr::from)?;
    let (new_hash, new_salt) = crypto::hash_password(&req.new_password);

    conn.execute(
        "UPDATE users SET password_hash = ?1, password_salt = ?2 WHERE id = ?3",
        rusqlite::params![new_hash, new_salt, user.user_id],
    )
    .map_err(ApiErr::from_db("change_password update"))?;

    Ok(Json(serde_json::json!({"ok": true})))
}

